const a = [
  {"id":1694,"text":"Which of the following features, according to Light's criteria, is suggestive of exudative effusion?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 564.","responses":[{"text":"Pleural fluid LDH : serum LDH ratio \u003e 0.6","correct":true,"visible":false},{"text":"Pleural fluid protein : serum protein ratio \u003c 0.5","correct":false,"visible":false},{"text":"Protein content of fluid \u003c 30 g/L","correct":false,"visible":false},{"text":"Pleural fluid LDH \u003c 2/3 of upper limit of normal serum LDH","correct":false,"visible":false},{"text":"Pleural fluid glucose is higher than serum glucose","correct":false,"visible":false}]},{"id":1700,"text":"Which one of the following drugs is not used for productive cough?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 528.","responses":[{"text":"Vasaka","correct":false,"visible":false},{"text":"Guaiacol","correct":false,"visible":false},{"text":"Bromhexine","correct":false,"visible":false},{"text":"Benzonatate","correct":true,"visible":false},{"text":"Acetyl cystine","correct":false,"visible":false}]},{"id":1701,"text":"What is the extra volume of air that can be inspired over and above the normal tidal volume, when the person inspires with full force, called?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 495.","responses":[{"text":"Expiratory reserve volume","correct":false,"visible":false},{"text":"Residual volume","correct":false,"visible":false},{"text":"Inspiratory reserve volume","correct":true,"visible":false},{"text":"Alveolar volume","correct":false,"visible":false},{"text":"Tidal volume","correct":false,"visible":false}]},{"id":1739,"text":"In which of the following diseases does the total lung capacity decrease?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 699.","responses":[{"text":"Emphysema","correct":false,"visible":false},{"text":"Chronic bronchitis","correct":false,"visible":false},{"text":"Bronchiectasis","correct":false,"visible":false},{"text":"Asthma","correct":false,"visible":false},{"text":"Pneumoconiosis","correct":true,"visible":false}]},{"id":1785,"text":"Which of the following is the major air pollutant of indoor smoke?","explanation":null,"reference":"Respiratory module, Community-medicine lecture slides, Topic: Air pollution, Sub-topic: Indoor air pollution.","responses":[{"text":"Carbon monoxide","correct":true,"visible":false},{"text":"Nitrous oxide","correct":false,"visible":false},{"text":"Carbon dioxide","correct":false,"visible":false},{"text":"Sulphur dioxide","correct":false,"visible":false},{"text":"Nitrogen dioxide","correct":false,"visible":false}]},{"id":1786,"text":"Ziehl–Neelsen staining is an important tool in the diagnosis of Mycobacterium tuberculosis. Its cell wall resists decolorization with acid due to the presence of which of the following?","explanation":null,"reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 6.","responses":[{"text":"Mycolic acid","correct":true,"visible":false},{"text":"Teichoic acid","correct":false,"visible":false},{"text":"Capsule","correct":false,"visible":false},{"text":"Lipids","correct":false,"visible":false},{"text":"Protein channels","correct":false,"visible":false}]},{"id":1787,"text":"A 20-year-old male presents with fever and cough for 3 weeks. After 2 weeks, he develops a headache and an altered level of consciousness. On examination, his temperature is 101°F. CNS examination reveals right-sided weakness with signs of meningeal irritation. CSF shows increased proteins, decreased glucose, and increased WBCs with predominant lymphocytes. What is the likely possibility?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 1078.","responses":[{"text":"Tuberculous meningitis (TBM)","correct":true,"visible":false},{"text":"Bacterial meningitis","correct":false,"visible":false},{"text":"Cerebral malaria","correct":false,"visible":false},{"text":"Cerebrovascular accident","correct":false,"visible":false},{"text":"Viral encephalitis","correct":false,"visible":false}]},{"id":1788,"text":"A 38-year-old office worker presents with a high-grade fever and productive cough. On examination, he has a temperature of 102.8°F, and a bronchial breath sound on the left upper chest. Which organism for pneumonia is more common in people working in air-conditioned offices?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 704.","responses":[{"text":"Legionella pneumoniae","correct":true,"visible":false},{"text":"Mycoplasma pneumoniae","correct":false,"visible":false},{"text":"Streptococcus pneumoniae","correct":false,"visible":false},{"text":"Klebsiella pneumoniae","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false}]},{"id":1789,"text":"Vestibular toxicity is associated with which of the following drugs?","explanation":null,"reference":"1) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 194. \r\n\r\n2) Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 847.","responses":[{"text":"Ethionamide","correct":false,"visible":false},{"text":"Ethambutol","correct":false,"visible":false},{"text":"Rifabutin","correct":false,"visible":false},{"text":"Streptomycin","correct":true,"visible":false},{"text":"Cycloserine","correct":false,"visible":false}]},{"id":1790,"text":"A 35-year-old female brings her pleural fluid analysis report, which shows the exudative nature of pleural fluid with a high amylase level. She gives a history of upper abdominal pain and vomiting in the recent past. She also had pulmonary tuberculosis 10 years ago. She has now developed pleural effusion. What is the most likely cause of her current condition?","explanation":"The most likely cause of the patient's current condition, characterized by an exudative pleural effusion with a high amylase level, is **acute pancreatitis**. Acute pancreatitis is an inflammatory condition of the pancreas that can lead to the release of pancreatic enzymes into the bloodstream and surrounding tissues. In some cases, these enzymes can reach the pleural space, resulting in the presence of amylase in the pleural fluid.\r\n\r\nThe patient's history of upper abdominal pain and vomiting is suggestive of acute pancreatitis, as these are common symptoms associated with the condition. The previous history of pulmonary tuberculosis is unrelated to the current presentation.\r\n\r\nIt is important to note that other causes of exudative pleural effusion should also be considered and evaluated, such as malignancy or infections. However, given the high amylase level in the pleural fluid and the patient's clinical presentation, acute pancreatitis is the most likely cause in this scenario.","reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 563.","responses":[{"text":"Tuberculosis","correct":false,"visible":false},{"text":"Acute cholecystitis","correct":false,"visible":false},{"text":"Acute pancreatitis","correct":true,"visible":false},{"text":"Malignancy","correct":false,"visible":false},{"text":"Systemic lupus erythematosus","correct":false,"visible":false}]},{"id":1791,"text":"Caplan syndrome is associated with which of the following?","explanation":null,"reference":"1) Nemakayala DR, Surmachevska N, Ramphul K. Caplan syndrome. In: StatPearls. StatPearls Publishing; 2022. Accessed May 16, 2022. http://www.ncbi.nlm.nih.gov/books/NBK499886/\r\n\r\n\r\n2) Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 701.","responses":[{"text":"Silica","correct":true,"visible":false},{"text":"Barium sulfate","correct":false,"visible":false},{"text":"Asbestos","correct":false,"visible":false},{"text":"Beryllium","correct":false,"visible":false},{"text":"Bagasse","correct":false,"visible":false}]},{"id":1792,"text":"An adult woman presented to an ophthalmologist with decreased visual acuity and color blindness for green. She has been on anti-tuberculous therapy (ATT) for 1 month. Her fundoscopy was normal. The ophthalmologist asked her to stop which of the following drugs considering the cause of her symptoms?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 846.","responses":[{"text":"Streptomycin","correct":false,"visible":false},{"text":"Isoniazid","correct":false,"visible":false},{"text":"Rifampicin","correct":false,"visible":false},{"text":"Ethambutol","correct":true,"visible":false},{"text":"Pyrazinamide","correct":false,"visible":false}]},{"id":1793,"text":"Radiation hazard most commonly leads to which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n57.","responses":[{"text":"Genetic changes and malformations","correct":true,"visible":false},{"text":"Leukemia only","correct":false,"visible":false},{"text":"Death due to chronic liver failure","correct":false,"visible":false},{"text":"Shortening of life always","correct":false,"visible":false},{"text":"Coronary artery diseases","correct":false,"visible":false}]},{"id":1798,"text":"One of the deleterious effects of cigarette smoking is the functional deficiency of the alpha-1-antitrypsin enzyme. Which substance present in smoke has this action?","explanation":null,"reference":"Nowak D, Ruta U. Nicotine inhibits alpha-1-proteinase inhibitor inactivation by oxidants derived from human polymorphonuclear leukocytes. Published 1990. https://pubmed.ncbi.nlm.nih.gov/2167236/","responses":[{"text":"Nicotine","correct":false,"visible":false},{"text":"Oxidant","correct":true,"visible":false},{"text":"Antioxidant","correct":false,"visible":false},{"text":"Carbon monoxide","correct":false,"visible":false},{"text":"Nitrogen dioxide","correct":false,"visible":false}]},{"id":1799,"text":"An HIV-positive male presents with fever and cough with hemoptysis for the past 2 weeks. His sputum is acid-fast bacillus (AFB) smear-positive. He is started on antitubercular treatment (ATT) but even after 4 months, there is no response. The doctor suspects multi-drug resistance. Which is the usual/common resistant pattern?","explanation":null,"reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 182.","responses":[{"text":"Resistance to isoniazid (INH)","correct":false,"visible":false},{"text":"Resistance to all first-line drugs","correct":false,"visible":false},{"text":"Resistance to rifampicin","correct":false,"visible":false},{"text":"Resistance to isoniazid and rifampicin","correct":true,"visible":false},{"text":"Resistance to any 2 first-line drugs","correct":false,"visible":false}]},{"id":1800,"text":"A young female presented with a low-grade fever and dry cough for the past 6 months. On examination, there were bilateral fine crepitations. Investigations showed increased serum calcium levels and bilateral hilar lymphadenopathy on chest X-ray. What is the most probable diagnosis for this lady?","explanation":null,"reference":"1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 694.  \r\n\r\n2) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 609.","responses":[{"text":"Lung cancer","correct":false,"visible":false},{"text":"Pulmonary tuberculosis","correct":false,"visible":false},{"text":"Lymphoma","correct":false,"visible":false},{"text":"Interstitial pneumonitis","correct":false,"visible":false},{"text":"Sarcoidosis","correct":true,"visible":false}]},{"id":1801,"text":"Which of the following is not associated with sarcoidosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 93.","responses":[{"text":"Cardiac arrhythmias","correct":false,"visible":false},{"text":"Hypocalcemia","correct":true,"visible":false},{"text":"Erythema nodosum","correct":false,"visible":false},{"text":"Cranial nerve palsies","correct":false,"visible":false},{"text":"Arthralgia","correct":false,"visible":false}]},{"id":1803,"text":"What is the possible genetic factor of sarcoidosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 608.","responses":[{"text":"11:22 translocation","correct":false,"visible":false},{"text":"Associated with a certain HLA haplotype","correct":true,"visible":false},{"text":"Telomerase shortening","correct":false,"visible":false},{"text":"Deletion of chromosome IIp","correct":false,"visible":false},{"text":"Activation of transforming growth factor-beta 1 (TGF-β1)","correct":false,"visible":false}]},{"id":1825,"text":"A medicolegal doctor is called to perform a post-mortem examination. He gives an incision starting from one inch below the symphysis menti up to symphysis pubis without cutting the umbilicus. What is this incision called?","explanation":"The incision described, starting from one inch below the symphysis menti (chin) up to the symphysis pubis without cutting the umbilicus, is called an **I-shaped incision**. This incision is commonly used in forensic medicine and post-mortem examinations.\r\n\r\nThe I-shaped incision allows for easy access to the thoracic and abdominal cavities for examination of organs and structures. The incision begins at the chin and extends vertically down to the pubic region, following the midline of the body. By avoiding the umbilicus, it allows for a clear view and access to the organs without interfering with the abdominal structures.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 102.","responses":[{"text":"Modified Y-shaped- incision","correct":false,"visible":false},{"text":"Y-shaped incision","correct":false,"visible":false},{"text":"I-shaped incision","correct":true,"visible":false},{"text":"T-shaped incision","correct":false,"visible":false},{"text":"Cruciate incision","correct":false,"visible":false}]},{"id":1826,"text":"The arterial blood gas (ABG) analysis of a patient shows pH=7.31, PCO₂=24 mmHg, and HCO₃=12 mmol/L. What is the most likely metabolic disturbance?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 616.","responses":[{"text":"Partially compensated combined acidosis","correct":false,"visible":false},{"text":"Compensated metabolic acidosis","correct":false,"visible":false},{"text":"Partially compensated metabolic acidosis with respiratory alkalosis","correct":false,"visible":false},{"text":"Compensated combined acidosis","correct":false,"visible":false},{"text":"Partially compensated metabolic acidosis","correct":true,"visible":false}]},{"id":1827,"text":"A post-mortem examination of the lung of an elderly male shows destruction of smooth muscle and elastic tissue, chronic necrotizing inflammation, and dilation of bronchi and bronchioles. Which of the following is the most likely diagnosis in this patient?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 683.","responses":[{"text":"Bronchiectasis","correct":true,"visible":false},{"text":"Emphysema","correct":false,"visible":false},{"text":"Asthma","correct":false,"visible":false},{"text":"Bronchiolitis","correct":false,"visible":false},{"text":"Pulmonary embolism","correct":false,"visible":false}]},{"id":1828,"text":"A 24-year-old asthmatic lady becomes pregnant. On examination, she has severe bilateral bronchospasm. Which of the following complications might she develop due to uncontrolled asthma?","explanation":"Uncontrolled asthma in a pregnant woman can lead to various complications for both the mother and the fetus. One of the potential complications is **maternal eclampsia**.\r\n\r\nMaternal eclampsia, also known as preeclampsia with seizures, is a serious condition characterized by high blood pressure and seizures during pregnancy. Although the exact cause of eclampsia is not fully understood, it is believed to be related to abnormal placental development and poor blood supply to the placenta.\r\n\r\nIn the case of uncontrolled asthma, the persistent bronchospasm and inadequate oxygen supply to the mother can lead to decreased oxygen delivery to the placenta. This compromised oxygen supply can contribute to placental dysfunction and increase the risk of developing preeclampsia and eclampsia.\r\n\r\nMaternal eclampsia poses significant risks to both the mother and the fetus. It can result in maternal complications such as stroke, organ damage, and even maternal death. Additionally, it can cause fetal growth restriction, premature birth, and fetal distress.","reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 570.","responses":[{"text":"Maternal eclampsia","correct":true,"visible":false},{"text":"Fetal cardiac defects","correct":false,"visible":false},{"text":"Spina bifida","correct":false,"visible":false},{"text":"Intrauterine growth retardation","correct":false,"visible":false},{"text":"Post date delivery","correct":false,"visible":false}]},{"id":1829,"text":"A patient with tuberculosis develops bright orange-red-urine and calls his physician in panic. The patient has no other urinary tract symptoms. Which of the following medication is most likely to produce this side effect?","explanation":null,"reference":"1) Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 845.\r\n\r\n2) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 193.","responses":[{"text":"Isoniazid","correct":false,"visible":false},{"text":"Rifampin","correct":true,"visible":false},{"text":"Ethambutol","correct":false,"visible":false},{"text":"Streptomycin","correct":false,"visible":false},{"text":"Pyridoxine","correct":false,"visible":false}]},{"id":1830,"text":"A 25-year-old patient presents with sudden onset of flu-like symptoms followed by high-grade fever and chest pain. Chest X-ray shows bilateral cavitary pneumonia. Which of the following would be the most likely causative organism?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 584.","responses":[{"text":"Staphylococcus aureus","correct":true,"visible":false},{"text":"Streptococcus viridans","correct":false,"visible":false},{"text":"Klebsiella","correct":false,"visible":false},{"text":"Streptococcus pneumoniae","correct":false,"visible":false},{"text":"Pseudomonas","correct":false,"visible":false}]},{"id":1831,"text":"A 35-year-old female presents to the outpatient department with progressive shortness of breath and dry cough. She has a history of red eyes as well. Chest X-Ray shows bilateral hilar lymphadenopathy, widespread pulmonary lines, and honeycombing. Which of the following is the best diagnostic test?","explanation":"In a patient presenting with progressive shortness of breath, dry cough, red eyes, and radiographic findings of bilateral hilar lymphadenopathy, widespread pulmonary lines, and honeycombing, the most appropriate diagnostic test is a **lung biopsy**.\r\n\r\nThese clinical findings are suggestive of a granulomatous lung disease, and the differential diagnosis includes conditions such as sarcoidosis, hypersensitivity pneumonitis, and certain types of interstitial lung diseases.\r\n\r\nA lung biopsy allows for a definitive diagnosis by examining lung tissue histologically. It helps identify the presence of granulomas, their distribution, and other characteristic features that can differentiate between different causes of granulomatous lung disease.\r\n\r\nOther diagnostic tests such as serum ACE (angiotensin-converting enzyme) levels, bronchoalveolar lavage, high-resolution CT (HRCT), and pulmonary function tests can provide additional supportive information, but they may not provide a definitive diagnosis. The lung biopsy provides direct visualization and examination of lung tissue, which is essential for accurate diagnosis and appropriate management.","reference":"1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 693.\r\n\r\n\r\n2) Bokhari SRA, Zulfiqar H, Mansur A. Sarcoidosis. In: StatPearls. StatPearls Publishing; 2022. Accessed May 17, 2022. http://www.ncbi.nlm.nih.gov/books/NBK430687/\r\n\r\n3) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 607, 609-610.","responses":[{"text":"Lung biopsy","correct":true,"visible":false},{"text":"Serum ACE level","correct":false,"visible":false},{"text":"Pulmonary function test","correct":false,"visible":false},{"text":"Chest high-resolution CT (HRCT)","correct":false,"visible":false},{"text":"Bronchoalveolar lavage","correct":false,"visible":false}]},{"id":1832,"text":"A 45-year-old female presents to the outpatient department with progressive shortness of breath and dry cough. She has a history of joint pain and red eyes as well. Chest X-ray shows bilateral hilar lymphadenopathy, widespread pulmonary lines, and honeycombing. Which of the following would the patient be suffering from?","explanation":"**Sarcoidosis** is a multisystem inflammatory disease that primarily affects the lungs and lymph nodes. It can also involve other organs such as the skin, eyes, heart, and joints. The condition is characterized by the formation of **non-caseating granulomas**, which are small clusters of immune cells, in affected tissues.\r\n\r\nThe **bilateral hilar lymphadenopathy, widespread pulmonary lines (reticular shadowing)**, and **honeycombing** seen on the chest X-ray are consistent with the characteristic radiographic findings of sarcoidosis. The presence of joint pain and red eyes further supports the diagnosis, as these extrapulmonary manifestations are commonly associated with sarcoidosis.","reference":"1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 694.\r\n\r\n\r\n2) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 610.\r\n\r\n3) Bokhari SRA, Zulfiqar H, Mansur A. Sarcoidosis. In: StatPearls. StatPearls Publishing; 2022. Accessed May 17, 2022. http://www.ncbi.nlm.nih.gov/books/NBK430687/","responses":[{"text":"Sarcoidosis","correct":true,"visible":false},{"text":"Tuberculosis","correct":false,"visible":false},{"text":"Pneumoconiosis","correct":false,"visible":false},{"text":"Alveolar cell carcinoma","correct":false,"visible":false},{"text":"Cryptogenic fibrosing alveolitis","correct":false,"visible":false}]},{"id":1833,"text":"A 65-year-old known case of chronic obstructive pulmonary disease (COPD) and bronchiectasis is admitted to the intensive care unit with fever and shortness of breath. The patient is put on a mechanical ventilator. He then develops bronchopneumonia. What is the suitable choice of antibiotic to be used?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 579.","responses":[{"text":"Ciprofloxacillin and aminoglycoside","correct":false,"visible":false},{"text":"Penicillin and aminoglycoside","correct":false,"visible":false},{"text":"Ceftazidime and ciprofloxacin","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Ceftazidime and aminoglycoside","correct":false,"visible":false}]},{"id":1834,"text":"A 70-year-old male presents with high-grade fever and chest pain. Examination shows bronchial breathing affecting the right lower part suggesting consolidation. Which of the following will be used for severity assessment?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 583.","responses":[{"text":"ABG with PaO2 \u003c 8K Pa","correct":false,"visible":false},{"text":"Age \u003e 65","correct":false,"visible":false},{"text":"Bilateral lower lobe involvement","correct":false,"visible":false},{"text":"ABG with SaO2 \u003c 92%","correct":false,"visible":false},{"text":"CURB-65","correct":true,"visible":false}]},{"id":1835,"text":"A 12-year-old boy came to the emergency department with complaints of abrupt onset of high fever with shaking chills, productive cough, and mucopurulent sputum. On gram stain, numerous pus cells with gram-positive lancet-shaped diplococci were observed. Which of the following is the most likely organism?","explanation":"The most likely organism causing the infection in the 12-year-old boy is ***Streptococcus pneumoniae***. *Streptococcus pneumoniae* is a gram-positive bacterium that commonly causes **community-acquired pneumonia** in children and adults. \r\n\r\nIt is characterized by **lancet-shaped diplococci**, and the presence of numerous pus cells suggests an inflammatory response to the infection. Streptococcus pneumoniae is a common cause of bacterial pneumonia and is known to produce symptoms such as high fever, shaking chills, productive cough, and mucopurulent sputum.","reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 119.","responses":[{"text":"Streptococcus pneumoniae","correct":true,"visible":false},{"text":"Hemophilus influenzae","correct":false,"visible":false},{"text":"Moraxella catarrhalis","correct":false,"visible":false},{"text":"Legionella pneumophila","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false}]},{"id":1836,"text":"A 2-year-old girl is brought to the emergency room with complaints of high-grade fever, noisy breathing, and drooling for 1 day. On examination, temperature = 104°F and respiratory rate = 60/min. What is the most likely diagnosis?","explanation":"In a 2-year-old girl presenting with high-grade fever, noisy breathing, drooling, and respiratory distress, the most likely diagnosis is **epiglottitis**. \r\n\r\nEpiglottitis is a severe bacterial infection involving the epiglottis and surrounding structures, usually caused by Haemophilus influenzae type B (Hib) bacteria. It typically presents with sudden onset of symptoms, including high fever, sore throat, difficulty swallowing, and respiratory distress. The child may prefer to sit upright and may exhibit a characteristic \"sniffing dog\" position to maintain airway patency.\r\n\r\nThe presence of drooling, noisy breathing, and respiratory distress is concerning for upper airway obstruction, a characteristic feature of epiglottitis. The high fever further supports this diagnosis.\r\n\r\nPrompt recognition and management are crucial in epiglottitis to prevent life-threatening airway compromise. The child should be stabilized with appropriate airway support, and intravenous antibiotics effective against Hib should be initiated.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 85.","responses":[{"text":"Epiglottitis","correct":true,"visible":false},{"text":"Peritonsillar abscess","correct":false,"visible":false},{"text":"Spasmodic croup","correct":false,"visible":false},{"text":"Bacterial tracheitis","correct":false,"visible":false},{"text":"Acute laryngeotracheobronchtis","correct":false,"visible":false}]},{"id":1837,"text":"A 26-year-old housewife develops a high-grade fever, cough with purulent sputum, and pleuritic type of chest pain. The lady was previously in a good state of health. What is the most probable diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n705.","responses":[{"text":"Acute exacerbation of chronic bronchitis","correct":false,"visible":false},{"text":"Bacterial pneumonia","correct":true,"visible":false},{"text":"Emphysema","correct":false,"visible":false},{"text":"Pulmonary tuberculosis","correct":false,"visible":false},{"text":"Bronchiectasis","correct":false,"visible":false}]},{"id":1838,"text":"A 26-year-old woman comes to the hospital due to dyspnea on mild exertion. The patient has no other medical conditions or addictions and is not currently on any medication. Her mother had similar symptoms and died at the age of 42 years. After an extensive workup, a lung biopsy is performed which shows medial hypertrophy, intimal fibrosis, and decreased intraluminal diameter of small branches of the pulmonary artery. Which of the following best describes this condition?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 700.","responses":[{"text":"Bronchiectasis","correct":false,"visible":false},{"text":"Pulmonary hypertension","correct":true,"visible":false},{"text":"Chronic obstructive pulmonary disease","correct":false,"visible":false},{"text":"Asthma","correct":false,"visible":false},{"text":"Emphysema","correct":false,"visible":false}]},{"id":1839,"text":"A 4-year-old boy has a 1-month history of recurrent cough with wheezing. There is no history of previous similar complaints and no family history of asthma or tuberculosis. Examination shows enlarged cervical nodes and bronchi. Chest X-Ray shows air trapping on the right side during inspiration. Which of the following is the most likely diagnosis?","explanation":"In a 4-year-old boy with a 1-month history of recurrent cough with wheezing, enlarged cervical nodes, and findings of air trapping on chest X-ray, the most likely diagnosis is **foreign body aspiration**.\r\n\r\nForeign body aspiration occurs when a foreign object enters the airway and obstructs the bronchi, leading to respiratory symptoms such as cough, wheezing, and difficulty breathing. It commonly occurs in young children who tend to explore objects by putting them in their mouths.\r\n\r\nThe presence of wheezing and air trapping on the right side during inspiration suggests partial obstruction of the right main bronchus, causing air to be trapped in the affected lung segment.\r\n\r\nEnlarged cervical nodes may indicate reactive lymphadenopathy due to the presence of an inflammatory process in the airways.\r\n\r\nA thorough history, clinical examination, and imaging findings support the diagnosis of foreign body aspiration in this case. Prompt evaluation and appropriate intervention, such as bronchoscopy, are necessary to remove the foreign object and relieve the obstruction.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n669, 671, 683.","responses":[{"text":"Nodal tuberculosis","correct":false,"visible":false},{"text":"Reactive airway disease","correct":false,"visible":false},{"text":"Foreign body aspiration","correct":true,"visible":false},{"text":"Gastro esophageal reflux","correct":false,"visible":false},{"text":"Right middle lobe syndrome","correct":false,"visible":false}]},{"id":1840,"text":"A 40-year-old known asthmatic patient is brought to the emergency room due to severe exacerbation of asthma. He must be given oxygen and frequent administration of corticosteroid with which of the following?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 572.","responses":[{"text":"Cromolyn","correct":false,"visible":false},{"text":"Ipratropium","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Salbutamol","correct":true,"visible":false},{"text":"Zileuton","correct":false,"visible":false}]},{"id":1841,"text":"A 3-year-old boy is brought with complaints of difficulty in breathing, noisy harsh sounds produced during inspiration, and high-grade fever for 2 days. What will be the most likely diagnosis?","explanation":"Based on the symptoms described (difficulty in breathing, noisy harsh sounds during inspiration, and high-grade fever), the most likely diagnosis in this case is **epiglottitis**. Epiglottitis is an inflammation of the epiglottis, a flap of tissue that covers the entrance of the trachea during swallowing to prevent food and liquid from entering the airway. It is commonly caused by a bacterial infection, most commonly by ***Haemophilus influenzae*** **type B (Hib)** bacteria.\r\n\r\nEpiglottitis is a serious condition that can rapidly progress and cause airway obstruction, leading to respiratory distress.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 85.","responses":[{"text":"Laryngitis","correct":false,"visible":false},{"text":"Bacterial tracheitis","correct":false,"visible":false},{"text":"Epiglottitis","correct":true,"visible":false},{"text":"Foreign body inhalation","correct":false,"visible":false},{"text":"Acute laryngotracheobronchitis (croup)","correct":false,"visible":false}]},{"id":1842,"text":"A 6-year-old male child is brought to the emergency room because of recurrent wheezing. He is on inhaled steroids. His mother gives a history that he has daytime symptoms\u003e 2/week and nighttime symptoms \u003e 2/months. On spirometry, his FEV is \u003e 80% with a PEF variability of 30%. He gets diagnosed with asthma. What is the classification of severity of asthma in this patient?","explanation":"The classification of asthma severity is based on the frequency and severity of symptoms, as well as lung function measurements. In this case, the child has daytime symptoms more than two times per week and nighttime symptoms more than two times per month, which places him in the category of persistent asthma.\r\n\r\nThe spirometry results show that his forced expiratory volume (FEV) is greater than 80%, indicating mild airflow limitation. The peak expiratory flow (PEF) variability of 30% suggests some variability in lung function.\r\n\r\nAccording to the Global Initiative for Asthma (GINA) guidelines, **mild persistent asthma** is characterized by symptoms occurring more than twice a week, but not daily, and nighttime symptoms more than twice a month. Lung function measurements, such as FEV, are usually greater than 80%, and PEF variability is greater than 20% but less than 30%.","reference":"1) Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 530.\r\n\r\n2) Dusser D, Montani D, Chanez P, et al. Mild asthma: an expert review on epidemiology, clinical characteristics and treatment recommendations. Allergy.","responses":[{"text":"Severe persistent asthma","correct":false,"visible":false},{"text":"Mild intermittent asthma","correct":false,"visible":false},{"text":"Mild persistent asthma","correct":true,"visible":false},{"text":"Cough variant asthma","correct":false,"visible":false},{"text":"Moderate persistent asthma","correct":false,"visible":false}]},{"id":1843,"text":"A 6-year-old child has a sudden onset of dyspnea with wheezing. On physical examination, he is afebrile but has absent breath sounds on the right. His temperature = 37 °C, pulse \r\n= 82/minute, respiratory rate = 28/minute, and blood pressure = 100/60 mm Hg. An arterial blood gas measurement shows pO2 = 95 mm Hg, pCO2 = 25 mm Hg, and pH = 7.55. Following the administration of 100% FiO2 by nasal canula, a repeat measurement shows pO2 = 95 mm Hg, pCO2 = 25 mm Hg, and pH = 7.55. Which of the following is the most likely diagnosis?","explanation":"The most likely diagnosis in this case is **foreign body aspiration**. The sudden onset of **dyspnea with wheezing, absent breath sounds on one side**, and the absence of fever suggests a localized obstruction of the airway. Foreign body aspiration occurs when an object is inhaled into the airway, leading to partial or complete blockage of the bronchus. This can cause localized wheezing and decreased breath sounds on the affected side.\r\n\r\nThe arterial blood gas measurement showing normal oxygenation (pO2 = 95 mm Hg) and low carbon dioxide levels (pCO2 = 25 mm Hg) indicates a ventilation-perfusion mismatch, which is commonly seen in cases of airway obstruction.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 671.","responses":[{"text":"Paraseptal emphysema","correct":false,"visible":false},{"text":"Thromboembolism","correct":false,"visible":false},{"text":"Foreign body aspiration","correct":true,"visible":false},{"text":"Pulmonary edema","correct":false,"visible":false},{"text":"Bronchial asthma","correct":false,"visible":false}]},{"id":1844,"text":"A 65-year-old man comes to the emergency department due to the sudden onset of shortness of breath and chest pain that started a few hours ago. He has been immobilized due to left leg pain and calf swelling for the past 30 days. The patient has no other medical condition, no addiction, and takes no medication. His temperature = 36 °C, blood pressure = 80/60, pulse = 112 min, respiratory rate = 30/min. Chest X-Ray reveals a wedge shaped infiltrate. Which of the following best describes this condition?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 697-698.","responses":[{"text":"Chronic obstructive pulmonary diease","correct":false,"visible":false},{"text":"Pulmonary embolism","correct":true,"visible":false},{"text":"Asthma","correct":false,"visible":false},{"text":"Pulmonary hypertension","correct":false,"visible":false},{"text":"Emphysema","correct":false,"visible":false}]},{"id":1845,"text":"A middle-aged male presents with a two-week history of severe shortness of breath and fever. On examination, he is cyanosed with bilateral coarse crepitations all over the chest. Chest X-Ray shows bilateral lung infiltrates, with O2 saturation of 88% on room air. What is the next best investigation as part of management?","explanation":"The next best investigation as part of the management in this case would be a **high-resolution CT (HRCT) scan**.\r\n\r\nThe clinical presentation of severe shortness of breath, fever, bilateral lung infiltrates, and low oxygen saturation raises suspicion of a significant lung pathology such as diffuse parenchymal lung disease. HRCT is a valuable imaging modality that provides detailed and high-resolution images of the lung parenchyma, allowing for the evaluation of lung architecture and identification of specific abnormalities. It can help differentiate between different lung conditions, such as pneumonia, interstitial lung disease, or pulmonary edema, which may present with similar clinical features.\r\n\r\nHRCT is particularly useful in this case because it can provide additional information about the extent and distribution of the lung infiltrates, the presence of any underlying lung pathology, and help guide further management decisions. It can also assist in the diagnosis of specific conditions, such as identifying characteristic patterns in interstitial lung diseases.","reference":"1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 605.\r\n\r\n2) Masood I, Elyassi W, Rind W. Medicine. 3rd ed. Majeed Sons; 2018: 241.","responses":[{"text":"Complete blood count","correct":false,"visible":false},{"text":"ESR and CRP","correct":false,"visible":false},{"text":"Bronchoscopy","correct":false,"visible":false},{"text":"High resolution CT","correct":true,"visible":false},{"text":"Arterial blood gases","correct":false,"visible":false}]},{"id":1846,"text":"A patient is taking some kind of RNA synthesis inhibitor for the treatment of a mycobacterium infection. They return back to the clinic extremely worried about recent events. They claim their urine, saliva, sweat, tears, and feces are all reddish-orange in color. What drug is the patient most likely to be taking?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 845","responses":[{"text":"Rifampin","correct":true,"visible":false},{"text":"Cycloserine","correct":false,"visible":false},{"text":"Streptomycin","correct":false,"visible":false},{"text":"Ethambutol","correct":false,"visible":false},{"text":"Isoniazide","correct":false,"visible":false}]},{"id":1848,"text":"A 20-year-old thin, tall boy presented to the emergency room with sudden onset of cough, severe shortness of breath, and chest pain. He recently arrived from the USA after a 16-hour flight. Immediate chest X-Ray was advised with the suspicion of pneumothorax. Which chest examination finding best reveals pneumothorax?","explanation":"The finding that best reveals **pneumothorax** on chest examination is a hyper-resonant percussion note on the affected side.\r\n\r\nPercussion is a technique used to assess the underlying structures and air content in the lungs. In a normal lung, percussion produces a resonant sound. However, in the case of pneumothorax, where air accumulates in the pleural space, the affected lung becomes hyperinflated and less dense, resulting in a **hyper-resonant percussion note**. This means that the sound produced on percussion is louder and more resonant than expected.\r\n\r\nOther findings that may be present in pneumothorax include decreased breath sounds on auscultation on the affected side due to reduced air entry, and decreased chest movements on the affected side due to lung collapse.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 706.","responses":[{"text":"Dull percussion note on the affected side","correct":false,"visible":false},{"text":"Increased chest movements on the affected side","correct":false,"visible":false},{"text":"Resonant percussion note on the affected side","correct":false,"visible":false},{"text":"Hyper-resonant percussion note on the affected side","correct":true,"visible":false},{"text":"Increased breath sounds on auscultation on the affected side","correct":false,"visible":false}]},{"id":1849,"text":"A 20-year-old female presents with shortness of breath. On auscultation, bilateral rhonchi are audible. Spirometry shows an obstructive pattern with complete reversibility after bronchoconstriction. What is the most likely diagnosis?","explanation":null,"reference":"1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 567.\r\n\r\n\r\n\r\n2) Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 698.","responses":[{"text":"Coal worker pneumoconiosis","correct":false,"visible":false},{"text":"Interstitial lung disease","correct":false,"visible":false},{"text":"Silicosis","correct":false,"visible":false},{"text":"COPD","correct":false,"visible":false},{"text":"Bronchial asthma","correct":true,"visible":false}]},{"id":1850,"text":"A 28-year-old female came with acute shortness of breath for one day. She is experiencing night symptoms for the past 2 months. What is the cause of raised diffusion capacity for carbon monoxide (DLCO) in pulmonary function tests?","explanation":"DLCO measures the ability of the lungs to transfer carbon monoxide from inhaled air to the bloodstream. In **asthma**, the raised DLCO is attributed to increased ventilation-perfusion (V/Q) mismatch due to bronchoconstriction and airway inflammation. The airway inflammation causes a decrease in airway diameter and increased resistance, leading to airflow limitation and impaired ventilation. However, the alveolar-capillary membrane remains intact, allowing efficient gas exchange and resulting in an increased DLCO.\r\n\r\nIn conditions such as obstructive sleep apnea, emphysema, cardiac failure, and interstitial lung disease, the DLCO is usually reduced due to impaired gas exchange at the alveolar-capillary membrane. These conditions are associated with decreased lung compliance, structural lung abnormalities, and impaired diffusion capacity.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 699.","responses":[{"text":"Obstructive sleep apnea","correct":false,"visible":false},{"text":"Emphysema","correct":false,"visible":false},{"text":"Asthma","correct":true,"visible":false},{"text":"Interstitial lung disease","correct":false,"visible":false},{"text":"Cardiac failure","correct":false,"visible":false}]},{"id":1851,"text":"A 45-year-old male presents in the emergency department with shortness of breath, insidious in onset, and progressive with dry cough. On examination, there is cyanosis, clubbing, and end-inspiratory respiratory crepitation in bilateral lung fields. Which of the following investigation is most appropriate to establish a diagnosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 605.","responses":[{"text":"Chest high-resolution computed tomography (HRCT)","correct":true,"visible":false},{"text":"Lung biopsy","correct":false,"visible":false},{"text":"Pulmonary function test","correct":false,"visible":false},{"text":"Chest X-Ray","correct":false,"visible":false},{"text":"Bronchoalveolar lavage","correct":false,"visible":false}]},{"id":1852,"text":"A 50-year-old male patient presents to the outpatient clinic with shortness of breath which is gradual in onset along with dry cough for the last 5 years. On examination, there is the clubbing of fingers and bilateral basal end respiratory crackles are audible. Chest X-Ray shows bilateral lower lobe subpleural reticular shadowing. What is the most likely diagnosis?","explanation":"**Idiopathic pulmonary fibrosis** is a chronic progressive lung disease characterized by the formation of fibrotic tissue in the lungs. It predominantly affects older individuals and commonly presents with symptoms such as shortness of breath, dry cough, and fatigue. Clubbing of the fingers is also a characteristic finding in IPF.\r\n\r\nOn examination, bilateral basal end inspiratory crackles are commonly heard in patients with IPF. These crackles represent the sound of fibrotic lung tissue rubbing against each other during inspiration.\r\n\r\nChest X-ray findings of bilateral lower lobe subpleural reticular shadowing are also consistent with IPF. Reticular shadowing refers to a pattern of fine linear opacities that resemble a network or reticulum, and it is commonly seen in IPF.","reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 606.","responses":[{"text":"Rheumatoid lung","correct":false,"visible":false},{"text":"Idiopathic pulmonary fibrosis","correct":true,"visible":false},{"text":"Sarcoidosis","correct":false,"visible":false},{"text":"Hypersensitivity pneumonitis","correct":false,"visible":false},{"text":"Lymphangitis carcinomatosis","correct":false,"visible":false}]},{"id":1853,"text":"A 70-year-old male patient, a heavy smoker, previously diagnosed case of COPD, has presented with cough, hemoptysis, low-grade fever, significant weight loss, and anorexia. X-ray chest reveals a large, left-sided pleural effusion. Pleural fluid analysis is done which is suggestive of exudative pleural effusion, according to Light's criteria. According to Light's criteria, exudate is likely if which of the following criteria has been met?","explanation":"According to Light's criteria, exudative pleural effusion is likely if the **pleural fluid protein: serum protein ratio is greater than 0.5**. \r\n\r\nLight's criteria are used to differentiate between exudative and transudative pleural effusions. Exudative effusions are usually associated with underlying inflammatory or malignant conditions, while transudative effusions are typically caused by systemic factors such as heart failure or liver disease.\r\n\r\nIn this case, the patient's presentation of cough, hemoptysis, low-grade fever, weight loss, and anorexia along with the presence of a large, left-sided pleural effusion suggests an inflammatory or malignant etiology. The pleural fluid analysis revealing an exudative nature based on Light's criteria supports this possibility.","reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 564.","responses":[{"text":"Pleural fluid LDH: serum LDH ratio\u003c0.3","correct":false,"visible":false},{"text":"Pleural fluid protein: serum protein ratio \u003c0.5","correct":false,"visible":false},{"text":"Pleural fluid LDH: serum LDH ratio\u003c0.6","correct":false,"visible":false},{"text":"Pleural fluid protein: serum protein ratio \u003e0.5","correct":true,"visible":false},{"text":"Pleural fluid LDH \u003c two thirds of the upper limit of normal serum LDH","correct":false,"visible":false}]},{"id":1854,"text":"An adult male brought his chest X-Ray film having findings highly suggestive of post-primary tuberculosis. Which of the following radiological findings is consistent with that?","explanation":null,"reference":"1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 589.\r\n\r\n\r\n  \r\n   2) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 375.","responses":[{"text":"Small pleural effusion","correct":false,"visible":false},{"text":"Gohn's focus","correct":false,"visible":false},{"text":"Miliary mottling","correct":false,"visible":false},{"text":"Hilar lymphadenopathy","correct":false,"visible":false},{"text":"Apical patchy shadowing","correct":true,"visible":false}]},{"id":1855,"text":"An elderly female is admitted to the intensive care unit (ICU) for acute respiratory distress syndrome on the 4th day of total hip replacement for a fracture of the neck of the femur. Which of the following is the cause of acute respiratory distress syndrome in this patient?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n672.","responses":[{"text":"Thromboembolism","correct":false,"visible":false},{"text":"Disseminated intravascular coagulation","correct":false,"visible":false},{"text":"Infection","correct":false,"visible":false},{"text":"Fat embolism","correct":true,"visible":false},{"text":"Hemorrhage","correct":false,"visible":false}]},{"id":1856,"text":"Caplan syndrome consists of which of the following?","explanation":"Caplan syndrome is a specific clinical entity characterized by the presence of **rheumatoid arthritis (RA) in combination with pneumoconiosis**, particularly coal worker's pneumoconiosis or silicosis. It is important to note that Caplan syndrome is specifically associated with pneumoconiosis and not other forms of interstitial lung disease.\r\n\r\nThe syndrome was first described in coal miners with concomitant RA, but it can also occur in individuals exposed to other dust particles, such as silica. The pathogenesis of Caplan syndrome is not completely understood, but it is believed to involve the interaction between environmental exposures and an underlying genetic predisposition to developing RA.\r\n\r\nClinically, Caplan syndrome presents with characteristic nodular pulmonary opacities on chest radiographs, which are termed \"rheumatoid nodules.\" These nodules are typically found in the upper lobes of the lungs.","reference":"Nemakayala DR, Surmachevska N, Ramphul K. Caplan syndrome. In: StatPearls. StatPearls Publishing; 2022. Accessed May 16, 2022. http://www.ncbi.nlm.nih.gov/books/NBK499886/","responses":[{"text":"Asbestosis and tuberculosis","correct":false,"visible":false},{"text":"Silicosis and tuberculosis","correct":false,"visible":false},{"text":"Berriliosis","correct":false,"visible":false},{"text":"Pneumoconiosis  and rheumatoid arthritis","correct":true,"visible":false},{"text":"Byssinosis and rheumatoid arthritis","correct":false,"visible":false}]},{"id":1857,"text":"Clinical signs and symptoms of pulmonary embolism may mimic myocardial infarction. Which of the following is the most correct method of diagnosing pulmonary embolism?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 698.","responses":[{"text":"ECG","correct":false,"visible":false},{"text":"Chest X-ray","correct":false,"visible":false},{"text":"Venography","correct":false,"visible":false},{"text":"Radio isotope perfusion pulmonary scintigraphy","correct":false,"visible":false},{"text":"Pulmonary arteriography","correct":true,"visible":false}]},{"id":1858,"text":"Clinically, chronic obstructive pulmonary disease (COPD) include which of the following?","explanation":"Clinically, chronic obstructive pulmonary disease (COPD) encompasses two main subtypes: **chronic bronchitis and emphysema**. These two conditions share certain common features but also have distinct characteristics.\r\n\r\nChronic bronchitis is characterized by a chronic cough with sputum production for at least three months in two consecutive years. It is primarily a disease of the large airways, involving inflammation and narrowing of the bronchi. The chronic inflammation leads to increased mucus production and thickening of the bronchial walls, contributing to airflow limitation.\r\n\r\nEmphysema, on the other hand, is characterized by the destruction of the alveolar walls and loss of lung elasticity. This results in enlarged air spaces and decreased gas exchange surface area. Emphysema primarily affects the smaller airways and alveoli.\r\n\r\nIn clinical practice, many patients with COPD may exhibit features of both chronic bronchitis and emphysema to varying degrees, leading to overlapping symptoms and lung function abnormalities.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 674.","responses":[{"text":"Emphysema and asthma","correct":false,"visible":false},{"text":"Bronchiectasis and emphysema","correct":false,"visible":false},{"text":"Chronic bronchitis and emphysema","correct":true,"visible":false},{"text":"Emphysema and bronchiolitis","correct":false,"visible":false},{"text":"Asthma and bronchiectasis","correct":false,"visible":false}]},{"id":1859,"text":"An asthmatic female patient recovering from myocardial infarction is on several\r\nmedications per day, including aspirin. She complains of large bruises on her arms and\r\nlegs. Her laboratory reports show elevated alanine transaminase (ALT). Which of the following is most likely responsible for the increase in liver enzymes?","explanation":null,"reference":"1) Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 712.\r\n2) Bouchette D, Preuss CV. Zileuton. In: StatPearls. StatPearls Publishing; 2022. Accessed May 19, 2022. http://www.ncbi.nlm.nih.gov/books/NBK448202/","responses":[{"text":"Heparin","correct":false,"visible":false},{"text":"Zafirlukast","correct":false,"visible":false},{"text":"Zileuton","correct":true,"visible":false},{"text":"Albuterol","correct":false,"visible":false},{"text":"Aspirin","correct":false,"visible":false}]},{"id":1860,"text":"Which of the following is the mechanism of action of cromolyn?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 416.","responses":[{"text":"Inhibition of phosphodiesterase","correct":false,"visible":false},{"text":"Inhibition of delayed chloride channels","correct":false,"visible":false},{"text":"Blockage of muscarinic receptors","correct":false,"visible":false},{"text":"Activation of beta-adrenergic receptors","correct":false,"visible":false},{"text":"Inhibition of mast cell mediators release","correct":true,"visible":false}]},{"id":1862,"text":"Syndrome of inappropriate antidiuretic hormone secretion (SIADH) and ectopic adrenocorticotropic hormone (ACTH) secretion are paraneoplastic syndromes. These are associated with which type of bronchogenic carcinoma?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.","responses":[{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":false,"visible":false},{"text":"Small cell carcinoma","correct":true,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Carcinoid tumor","correct":false,"visible":false}]},{"id":1863,"text":"Which of the following subtype of lung cancer is most commonly found in females?","explanation":null,"reference":"1) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.\r\n2) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 714.","responses":[{"text":"Small cell carcinoma","correct":false,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":true,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Carcinoids","correct":false,"visible":false}]},{"id":1864,"text":"Hypercalcemia is the paraneoplastic syndrome associated with which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 719.","responses":[{"text":"Adenocarcinoma","correct":false,"visible":false},{"text":"Squamous cell cancer","correct":true,"visible":false},{"text":"Carcinoid tumor","correct":false,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Small cell carcinoma of lung","correct":false,"visible":false}]},{"id":1865,"text":"If pulmonary function test shows FEV1/FVC ratio less than 0.70 with increased total lung capacity (TLC), then the interpretation would be:","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 698.","responses":[{"text":"Restrictive pattern","correct":false,"visible":false},{"text":"Normal","correct":false,"visible":false},{"text":"Obstructive pattern","correct":true,"visible":false},{"text":"Non-specific reductions in FEV1 and FVC","correct":false,"visible":false},{"text":"Mixed pattern","correct":false,"visible":false}]},{"id":1881,"text":"In arterial blood gases, low pH and high CO2 are seen in which of the following conditions?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 616.","responses":[{"text":"Compensatory metabolic alkalosis","correct":false,"visible":false},{"text":"Metabolic acidosis","correct":false,"visible":false},{"text":"Respiratory alkalosis","correct":false,"visible":false},{"text":"Respiratory acidosis","correct":true,"visible":false},{"text":"Metabolic alkalosis","correct":false,"visible":false}]},{"id":1882,"text":"In tuberculosis, macrophages play an important role in antigen recognition and processing. They activate TH-1 cells through the production of which one of the important cytokines given below?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 372.","responses":[{"text":"IL-6","correct":false,"visible":false},{"text":"TNF","correct":false,"visible":false},{"text":"Defensins","correct":false,"visible":false},{"text":"IL-12","correct":true,"visible":false},{"text":"INF- Ɣ","correct":false,"visible":false}]},{"id":1883,"text":"Inhaled allergens in atopic asthma elicit TH2-dominated response IgE production and recruitment of which of the following cells?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 680.","responses":[{"text":"Dendritic cells","correct":false,"visible":false},{"text":"Macrophages","correct":false,"visible":false},{"text":"Neutrophils","correct":false,"visible":false},{"text":"Plasma cells","correct":false,"visible":false},{"text":"Eosinophils","correct":true,"visible":false}]},{"id":1884,"text":"Inhaled salbutamol is useful in bronchial asthma due to which of the following?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 88.","responses":[{"text":"Aborting/terminating asthma attacks","correct":true,"visible":false},{"text":"Status asthmaticus","correct":false,"visible":false},{"text":"Round the clock prophylaxis of asthma","correct":false,"visible":false},{"text":"Reduces inflammation","correct":false,"visible":false},{"text":"Suppresses hyper-reactivity","correct":false,"visible":false}]},{"id":1885,"text":"What is the interpretation of the following spirometry results; FEV1=3.35L (Patient's value); FVC=5.22 L (Patient's value), and FEV1/FVC ratio=0.64?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 89.","responses":[{"text":"Non-specific reductions in FEV1 and FVC","correct":false,"visible":false},{"text":"Restrictive pattern","correct":false,"visible":false},{"text":"Mixed pattern","correct":false,"visible":false},{"text":"Normal","correct":false,"visible":false},{"text":"Obstructive pattern","correct":true,"visible":false}]},{"id":1886,"text":"Lung cancers may be associated with paraneoplastic syndromes. Cushing syndrome develops as a paraneoplastic syndrome due to the production of which of the following hormones?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96, 159.","responses":[{"text":"Calcitonin","correct":false,"visible":false},{"text":"Anti diuretic hormone","correct":false,"visible":false},{"text":"Gonadotropins","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone","correct":true,"visible":false},{"text":"Parathormone","correct":false,"visible":false}]},{"id":1887,"text":"A 55-year-old patient with chronic obstructive pulmonary disease (COPD) is admitted with a complaint of increased shortness of breath, fever and cough. He was treated with antibiotics, bronchodilators and oxygen. On discharge, his resting SaO2 was 80%. Which of the following is the only drug therapy known to cause improvement in the natural history?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 361.","responses":[{"text":"Oxygen therapy","correct":false,"visible":false},{"text":"Inhaled bronchodilators","correct":true,"visible":false},{"text":"Corticosteroids","correct":false,"visible":false},{"text":"Theophylline","correct":false,"visible":false},{"text":"Smoking cessation","correct":false,"visible":false}]},{"id":1888,"text":"In which of the following conditions, Tardieu spots are not seen?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 161.","responses":[{"text":"Drowning","correct":true,"visible":false},{"text":"Traumatic asphyxia","correct":false,"visible":false},{"text":"Strangulation","correct":false,"visible":false},{"text":"Overlaying","correct":false,"visible":false},{"text":"Lynching","correct":false,"visible":false}]},{"id":1890,"text":"In case of suicidal death, an investigation conducted by friends and relatives of the deceased for collecting information and knowledge about mental status in order to justify the suicide is called:","explanation":"In cases of suicidal death, a **psychological autopsy** is conducted to gather information and gain insight into the mental state of the deceased individual leading up to the suicide. It is a methodical investigation performed by friends, family members, mental health professionals, and law enforcement personnel.\r\n\r\nThe purpose of a psychological autopsy is to collect information about the individual's life history, behavior, relationships, and any significant events or stressors preceding the suicide. This includes interviews with family members, friends, and healthcare providers, as well as a review of available medical and psychiatric records.\r\n\r\nThe aim of a psychological autopsy is to gain a comprehensive understanding of the individual's psychological well-being, including any signs of mental illness, suicidal ideation, or previous suicide attempts. The collected information can help in determining the factors that may have contributed to the suicide and provide insights for prevention and intervention strategies.","reference":"Respiratory module, Forensic-medicine lecture slides, Topic: Autopsy-I, Subtopic: Psychological autopsy.","responses":[{"text":"Death investigation","correct":false,"visible":false},{"text":"Medical autopsy","correct":false,"visible":false},{"text":"Psychological autopsy","correct":true,"visible":false},{"text":"Police autopsy","correct":false,"visible":false},{"text":"Forensic autopsy","correct":false,"visible":false}]},{"id":1891,"text":"Which of the following medium is used to grow Mycobacterium tuberculosis?","explanation":null,"reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 176.","responses":[{"text":"Löwenstein-Jensen medium","correct":true,"visible":false},{"text":"Triple sugar iron test","correct":false,"visible":false},{"text":"Blood agar","correct":false,"visible":false},{"text":"McConkeys Agar","correct":false,"visible":false},{"text":"Luria broth","correct":false,"visible":false}]},{"id":1892,"text":"The most common association of pneumothorax is:","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 722.","responses":[{"text":"Adenocarcinoma of the lung","correct":false,"visible":false},{"text":"Emphysema","correct":true,"visible":false},{"text":"Bronchiolitis","correct":false,"visible":false},{"text":"Chronic bronchiolitis","correct":false,"visible":false},{"text":"Mesothelioma","correct":false,"visible":false}]},{"id":1893,"text":"Mycobacterium tuberculosis resides in which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 371.","responses":[{"text":"Neutrophils","correct":false,"visible":false},{"text":"Eosinophils","correct":false,"visible":false},{"text":"Basophils","correct":false,"visible":false},{"text":"Lymphocytes","correct":false,"visible":false},{"text":"Macrophages","correct":true,"visible":false}]},{"id":1894,"text":"On the 11th day of operation of adenocarcinoma of the prostate, a 70-year-old man suddenly became extremely dyspneic and diaphoretic, with chest pain, palpitations, and a feeling of panic. Which of the following postoperative pulmonary complications is most likely to develop?","explanation":null,"reference":"1) Van Hemelrijck M, Garmo H, Holmberg L, et al. Thromboembolic events following surgery for prostate cancer. European Urology. Published February 2013. https://pubmed.ncbi.nlm.nih.gov/23021972/\r\n\r\n\r\n2) Van Hemelrijck M, Adolfsson J, Garmo H, et al. Risk of thromboembolic diseases in men with prostate cancer: results from the population-based PCBaSe Sweden. The Lancet. Oncology. Published May 11, 2010. Accessed May 19, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2861771/","responses":[{"text":"Pulmonary edema","correct":false,"visible":false},{"text":"Diffuse alveolar damage","correct":false,"visible":false},{"text":"Atelectasis","correct":false,"visible":false},{"text":"Thromboembolus","correct":true,"visible":false},{"text":"Pleural effusion","correct":false,"visible":false}]},{"id":1895,"text":"A convict charged with murder was sentenced with judicial hanging by the court of law. The cause of death in judicial hanging is?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 167.","responses":[{"text":"Separation of medulla oblongata from spinal cord","correct":false,"visible":false},{"text":"Vasovagal shock","correct":false,"visible":false},{"text":"Fracture and dislocation of 2nd cervical vertebrae","correct":true,"visible":false},{"text":"Congestive cardiac failure","correct":false,"visible":false},{"text":"Asphyxia due to compression of neck","correct":false,"visible":false}]},{"id":1896,"text":"A 4-year-old boy is brought to you with complaints of fever and cough, persistent for the past 6 weeks, and has lost his weight in this period. On examination, of the chest, crepitations and a wheeze are audible on the right side of the chest. Labs show hemoglobin (Hb) of 9 gm/dl, erythrocyte sedimentation rate (ESR) of 60 mm/hr, and induration in Mycobacterium tuberculin (MT) test is 11 mm. How will you treat?","explanation":"The patient's symptoms of fever, cough, and weight loss, along with the presence of crepitations and a wheeze on chest examination, raise suspicion for **tuberculosis (TB)**. The induration of 11 mm in the tuberculin (MT) test is significant and supports the diagnosis of TB.\r\n\r\nIn children, the standard treatment for active pulmonary tuberculosis is a combination of multiple antituberculous drugs for a duration of 6 months. The regimen typically includes **isoniazid, rifampicin, pyrazinamide**, and **ethambutol**. This multidrug therapy is effective in treating TB and preventing the development of drug resistance.\r\n\r\nThe use of broad-spectrum antibiotics or antipyretics alone would not be appropriate for the management of tuberculosis. Tuberculosis requires specific antituberculous therapy to eradicate the infection and prevent complications.","reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 593.","responses":[{"text":"6 months of antituberculous therapy","correct":true,"visible":false},{"text":"Broad spectrum antibiotic","correct":false,"visible":false},{"text":"Broad spectrum antibiotic with antipyretic","correct":false,"visible":false},{"text":"Antipyretic with antiallergy for 6 months","correct":false,"visible":false},{"text":"12 months of antituberculous therapy","correct":false,"visible":false}]},{"id":1897,"text":"Which of the following is a key component of photochemical smog?","explanation":"Photochemical smog is a type of air pollution that forms when sunlight reacts with certain pollutants in the atmosphere, primarily nitrogen oxides (NOx) and volatile organic compounds (VOCs). Ozone (O3) is formed as a result of these reactions.\r\n\r\nIn the presence of sunlight, nitrogen oxides and volatile organic compounds undergo a series of chemical reactions that produce a variety of pollutants, including ozone. **Ozone at ground level** is a harmful pollutant that can cause respiratory problems, eye irritation, and other health issues. It is different from the beneficial ozone layer in the upper atmosphere, which protects the Earth from harmful ultraviolet (UV) radiation.\r\n\r\nThe formation of ozone in photochemical smog is a complex process involving the interaction of sunlight, nitrogen oxides, and volatile organic compounds. These reactions occur primarily in urban and industrial areas where there are high levels of pollution from vehicles, industrial emissions, and other sources.","reference":"Lu H, Lyu X, Cheng H, Ling Z, Guo H. Overview on the spatial-temporal characteristics of the ozone formation regime in China. Environmental Science. Processes \u0026 Impacts.","responses":[{"text":"Ozone at ground level","correct":true,"visible":false},{"text":"Ozone layer in upper atmosphere","correct":false,"visible":false},{"text":"Hydrocarbons","correct":false,"visible":false},{"text":"Particulate matter","correct":false,"visible":false},{"text":"Biological pollutants","correct":false,"visible":false}]},{"id":1898,"text":"Pleural plaque is the most common manifestation of exposure to which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 93.","responses":[{"text":"Coal","correct":false,"visible":false},{"text":"Radiation","correct":false,"visible":false},{"text":"Asbestos","correct":true,"visible":false},{"text":"Silica","correct":false,"visible":false},{"text":"Beryllium","correct":false,"visible":false}]},{"id":1900,"text":"Regarding laryngeotracheobronchitis, the most frequently observed radiological finding is:","explanation":null,"reference":"Laryngotracheobronchitis - an overview | sciencedirect topics. Accessed May 17, 2022. https://www.sciencedirect.com/topics/pharmacology-toxicology-and-pharmaceutical-science/laryngotracheobronchitis","responses":[{"text":"Normal","correct":false,"visible":false},{"text":"Ragged tracheal border","correct":false,"visible":false},{"text":"Thickened nasopharyngeal space","correct":false,"visible":false},{"text":"Steeple sign","correct":true,"visible":false},{"text":"Thumb sign at epiglottis","correct":false,"visible":false}]},{"id":1901,"text":"Regarding occupational health, genetic changes are caused by:","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 432.","responses":[{"text":"Silica","correct":false,"visible":false},{"text":"Poor lighting","correct":false,"visible":false},{"text":"Ingestion of mercury","correct":false,"visible":false},{"text":"Radioactive radiations","correct":true,"visible":false},{"text":"Noise","correct":false,"visible":false}]},{"id":1903,"text":"Regarding the morphology of sarcoidosis, which of the following is correct?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 693.","responses":[{"text":"Central necrosis is common","correct":false,"visible":false},{"text":"Only the lung shows the classic granulomas","correct":false,"visible":false},{"text":"Asteroid bodies enclosed within giant cells are present","correct":true,"visible":false},{"text":"Schaumann bodies are pathognomonic for sarcoid","correct":false,"visible":false},{"text":"Lymph node involvement is rare","correct":false,"visible":false}]},{"id":1904,"text":"Rifampin is not indicated in which of the following conditions?","explanation":null,"reference":"(1) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 139, 193. (2) Holland TL, Fowler VG. Rifampicin for Staphylococcus aureus bacteraemia: give it ARREST. The Lancet. Published February 17, 2018. Accessed May 12, 2022. https://www.thelancet.com/journals/lancet/article/PIIS0140-6736(17)33294-4/fulltext (3) Euba G, Murillo O, Fernández-Sabé N, et al. Long-term follow-up trial of oral rifampin-cotrimoxazole combination versus intravenous cloxacillin in treatment of chronic staphylococcal osteomyelitis. Antimicrobial Agents and Chemotherapy. Published June 2009. Accessed May 12, 2022. https://journals.asm.org/doi/10.1128/AAC.01504-08","responses":[{"text":"Plaque","correct":true,"visible":false},{"text":"Endocarditis","correct":false,"visible":false},{"text":"Leprosy","correct":false,"visible":false},{"text":"Hemophilus influenzae","correct":false,"visible":false},{"text":"Staphylococcus osteomyelitis","correct":false,"visible":false}]},{"id":1905,"text":"Secondary mycobacterial infection should always be an important consideration in HIV-positive patients who present with pulmonary disease. Which of the following is the most common causative organism of this condition?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 374.","responses":[{"text":"M. leprae","correct":false,"visible":false},{"text":"M. kansasi","correct":false,"visible":false},{"text":"M. tuberculosis","correct":true,"visible":false},{"text":"M. scrofulaceum","correct":false,"visible":false},{"text":"M. avium complex","correct":false,"visible":false}]},{"id":1906,"text":"Which of the following is a long-acting β2-adrenergic agonist?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 712.","responses":[{"text":"Terbutaline","correct":false,"visible":false},{"text":"Salmeterol","correct":true,"visible":false},{"text":"Albuterol","correct":false,"visible":false},{"text":"Metaproterenol","correct":false,"visible":false},{"text":"Pirbuterol","correct":false,"visible":false}]},{"id":1907,"text":"Which of the following drugs is neither a bronchodilator nor an anti-inflammatory but has antihistaminic and mast cell stabilizing activity?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 495.","responses":[{"text":"Beclomethasone dipropionate","correct":false,"visible":false},{"text":"Ketotifen","correct":true,"visible":false},{"text":"Ipratropium","correct":false,"visible":false},{"text":"Chlorpheniramine","correct":false,"visible":false},{"text":"Sodium cromoglycate","correct":false,"visible":false}]},{"id":1908,"text":"Which of the following drugs blocks the 5-lipoxygenase enzyme and inhibits the synthesis of leukotriene?","explanation":"**Zileuton** is a drug that blocks the 5-lipoxygenase enzyme, thereby inhibiting the synthesis of leukotrienes. Leukotrienes are inflammatory mediators that play a significant role in the pathogenesis of asthma and other inflammatory conditions.\r\n\r\nBy inhibiting the action of 5-lipoxygenase, zileuton reduces the production of leukotrienes, specifically leukotriene B4, leukotriene C4, and leukotriene D4. These leukotrienes are known to cause bronchoconstriction, inflammation, and mucus production in the airways, leading to the symptoms of asthma.\r\n\r\nZileuton is used as a controller medication in the management of asthma. It helps to prevent and control asthma symptoms by reducing airway inflammation and improving lung function. It is particularly beneficial in patients with persistent asthma who have an inadequate response to other asthma medications.\r\n\r\nIt is important to note that zileuton may have some side effects, including liver function abnormalities, so regular monitoring of liver function is necessary during treatment.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 712.","responses":[{"text":"Montelukast","correct":false,"visible":false},{"text":"Zileuton","correct":true,"visible":false},{"text":"Zafirlukast","correct":false,"visible":false},{"text":"Azelastine","correct":false,"visible":false},{"text":"Omalizumab","correct":false,"visible":false}]},{"id":1909,"text":"Which of the following is the most serious adverse event associated with ethambutol?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 194.","responses":[{"text":"Hepatitis","correct":false,"visible":false},{"text":"Bone marrow suppression","correct":false,"visible":false},{"text":"Optic neuritis","correct":true,"visible":false},{"text":"Psychotic reaction","correct":false,"visible":false},{"text":"Nephritis","correct":false,"visible":false}]},{"id":1912,"text":"Smoking is associated with which of the following subtypes of emphysema?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 675.","responses":[{"text":"Distal acinar","correct":false,"visible":false},{"text":"Centriacinar","correct":true,"visible":false},{"text":"Paraseptal acinar","correct":false,"visible":false},{"text":"Septal acinar","correct":false,"visible":false},{"text":"Panacinar","correct":false,"visible":false}]},{"id":1913,"text":"Some of the pulmonary disorders are characterized by irreversible enlargement of air spaces distal to terminal bronchioles accompanied by destruction of their walls and without any obvious fibrosis. Which of the following conditions best characterizes the above statement?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 675.","responses":[{"text":"Idiopathic pulmonary fibrosis","correct":false,"visible":false},{"text":"Emphysema","correct":true,"visible":false},{"text":"Bronchiectasis","correct":false,"visible":false},{"text":"Asthma","correct":false,"visible":false},{"text":"Bronchitis","correct":false,"visible":false}]},{"id":1914,"text":"Spirometry is a clinical test used to assess the severity of diffuse pulmonary diseases that could be obstructive or restrictive. In which one of the following conditions is there a proportionate decrease in total lung capacity and forced expiratory volume in 1 sec (FEV1/FCV = normal)?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 699.","responses":[{"text":"Bronchiolitis","correct":false,"visible":false},{"text":"Idiopathic pulmonary fibrosis","correct":true,"visible":false},{"text":"Bronchial asthma","correct":false,"visible":false},{"text":"Bronchiectasis","correct":false,"visible":false},{"text":"Chronic bronchitis","correct":false,"visible":false}]},{"id":1915,"text":"What is the amount of air a person can breathe in beginning at the normal expiratory level and distending the lungs to the maximum amount?","explanation":"The **inspiratory capacity** is a measurement of lung volume that represents the maximum volume of air a person can inspire after a normal expiration.\r\n\r\nThe inspiratory capacity is calculated by adding the tidal volume (the volume of air inspired and expired during normal breathing) to the inspiratory reserve volume (the additional volume of air that can be inhaled after a normal inspiration).\r\n\r\nThe inspiratory capacity provides valuable information about lung function and respiratory health. It is often measured during pulmonary function tests to assess lung volumes and capacities, diagnose respiratory conditions, and monitor disease progression or response to treatment.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 688.","responses":[{"text":"Functional residual capacity","correct":false,"visible":false},{"text":"Expiratory capacity","correct":false,"visible":false},{"text":"Inspiratory capacity","correct":true,"visible":false},{"text":"Total lung capacity","correct":false,"visible":false},{"text":"Vital capacity","correct":false,"visible":false}]},{"id":1916,"text":"The DNA damage due to radicals formed as a result of radiation is an example of which of the following?","explanation":"The DNA damage caused by radicals formed as a result of radiation is an example of **indirect damage**. Indirect damage refers to the damage caused by the reactive intermediates generated by the interaction of radiation with molecules in the body, rather than direct interaction between the radiation and DNA.\r\n\r\nWhen ionizing radiation interacts with water molecules in the body, it produces free radicals, such as hydroxyl radicals (·OH), which are highly reactive and can cause oxidative damage to DNA. These free radicals can directly attack the DNA molecule, leading to DNA strand breaks, base modifications, and other types of DNA damage.\r\n\r\nThe DNA damage caused by these radicals can have various biological consequences, including cell death, mutations, and potentially the development of cancer.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 429.","responses":[{"text":"Splitting of chemical bonds","correct":false,"visible":false},{"text":"Accidental damage","correct":false,"visible":false},{"text":"Indirect damage","correct":true,"visible":false},{"text":"Direct damage","correct":false,"visible":false},{"text":"Threshold level damage","correct":false,"visible":false}]},{"id":1917,"text":"What is the extra volume of air that can be expired above the tidal volume, upon full expiration, called?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 495.","responses":[{"text":"Inspiratory reserve volume","correct":false,"visible":false},{"text":"Residual volume","correct":false,"visible":false},{"text":"Tidal volume","correct":false,"visible":false},{"text":"Alveolar volume","correct":false,"visible":false},{"text":"Expiratory reserve volume","correct":true,"visible":false}]},{"id":1918,"text":"Which of these is a life-saving drug given parenterally in severe status asthmaticus that will act by inhibiting phospholipase A2?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 384.","responses":[{"text":"Metaproterenol","correct":false,"visible":false},{"text":"Aminophylline","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Salbutamol","correct":false,"visible":false},{"text":"Prednisone","correct":true,"visible":false}]},{"id":1920,"text":"Which of the following is the most important cause of panacinar (panlobular) emphysema?","explanation":"The most important cause of panacinar (panlobular) emphysema, a type of chronic obstructive pulmonary disease (COPD), is **alpha 1 antitrypsin deficiency**. Alpha 1 antitrypsin is a protein produced by the liver that helps protect the lungs from the damaging effects of enzymes called proteases. In individuals with alpha 1 antitrypsin deficiency, there is a decreased production or abnormal function of this protein, leading to an imbalance between proteases and their inhibitors in the lung tissue.\r\n\r\nPanacinar emphysema is characterized by the destruction of alveolar walls throughout the entire respiratory acinus, from the respiratory bronchioles to the alveoli. This leads to the enlargement of air spaces and loss of elastic recoil, resulting in air trapping and impaired airflow. While cigarette smoking is the most common cause of emphysema overall, alpha 1 antitrypsin deficiency is specifically associated with the development of panacinar emphysema, especially in younger individuals with a family history of the condition.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 675.","responses":[{"text":"Occupational dust","correct":false,"visible":false},{"text":"Alpha 1 antitrypsin deficiency","correct":true,"visible":false},{"text":"Cigarette smoking","correct":false,"visible":false},{"text":"Air pollution","correct":false,"visible":false},{"text":"Infection","correct":false,"visible":false}]},{"id":1921,"text":"The type of asphyxia that is associated with anesthesia and surgical maneuvers is termed as:","explanation":"The type of asphyxia that is associated with anesthesia and surgical maneuvers is termed **iatrogenic asphyxia**. \"Iatrogenic\" refers to conditions or complications that are caused by medical intervention or treatment.\r\n\r\nDuring anesthesia and surgical procedures, there can be various factors that contribute to iatrogenic asphyxia. These may include airway obstruction, inadequate ventilation, or compromised oxygenation due to the effects of anesthesia or surgical manipulation.\r\n\r\nExamples of situations that can lead to iatrogenic asphyxia include the accidental placement of an endotracheal tube in the esophagus instead of the trachea, inadequate oxygen supply during surgery, or complications such as laryngospasm or bronchospasm.\r\n\r\nPrompt recognition and intervention are crucial in managing iatrogenic asphyxia to prevent severe respiratory compromise and potential adverse outcomes.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 161.","responses":[{"text":"Mechanical asphyxia","correct":false,"visible":false},{"text":"Clinical asphyxia","correct":false,"visible":false},{"text":"Iatrogenic asphyxia","correct":true,"visible":false},{"text":"Pathological asphyxia","correct":false,"visible":false},{"text":"Toxic asphyxia","correct":false,"visible":false}]},{"id":1922,"text":"According to the Integrated Management of Neonatal and Childhood Illnesses (IMNCI), tuberculosis vaccine is given:","explanation":null,"reference":"Hematology module, Community-medicine lecture slides, Topic: Vaccination, Sub-topic: EPI vaccination schedule.","responses":[{"text":"At birth intradermally on left thigh","correct":false,"visible":false},{"text":"At birth intradermally over right deltoid region","correct":true,"visible":false},{"text":"At 6 weeks of age along with hep B vaccine","correct":false,"visible":false},{"text":"At 6 weeks of age intradermally on left deltoid","correct":false,"visible":false},{"text":"At 9 months of age on left thigh","correct":false,"visible":false}]},{"id":1923,"text":"A medico-legal doctor is performing the autopsy for the opening of the skull during post-mortem in a newborn baby. How should the incision be done?","explanation":"During the autopsy of a newborn baby, the incision for opening the skull is typically done by opening the **sagittal and coronal sutures**. The sagittal suture is the main suture that runs along the midline of the skull from the anterior fontanelle (soft spot) to the posterior fontanelle. The coronal suture runs horizontally from one side of the skull to the other.\r\n\r\nTo open the skull, the medico-legal doctor makes a cut along the sagittal suture and then continues the incision along the coronal suture. This allows for a flap-like opening of the skull, providing access to the brain and its structures.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 321.","responses":[{"text":"Over the top of the head from right ear to the left ear","correct":false,"visible":false},{"text":"Cutting from mastoid to mastoid","correct":false,"visible":false},{"text":"Opening of sagittal + coronal sutures","correct":true,"visible":false},{"text":"Cutting along sagittal sutures","correct":false,"visible":false},{"text":"Making a circular cut","correct":false,"visible":false}]},{"id":1924,"text":"The most important difference between a forensic autopsy and a pathological autopsy is that in forensic autopsy:","explanation":"The most important difference between a forensic autopsy and a pathological autopsy is that a forensic autopsy is a **valid documentary evidence in the court of law**. Forensic autopsies are performed in cases of unnatural, sudden, or suspicious deaths with the primary purpose of gathering evidence and determining the cause and manner of death. The findings and documentation from a forensic autopsy can be presented as evidence in legal proceedings.\r\n\r\nWhile both forensic and pathological autopsies involve the examination of the deceased, the focus and objectives differ. Pathological autopsies are primarily performed to study the underlying disease processes and understand the cause of death for medical and research purposes. In contrast, forensic autopsies are conducted within a legal framework to investigate potential crimes, determine the cause of death, identify any injuries or signs of foul play, and provide expert testimony in legal proceedings.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 98.","responses":[{"text":"All cavities are opened even if injury is not found","correct":false,"visible":false},{"text":"Cause of death is usually not known but has to be determined","correct":false,"visible":false},{"text":"It is a valid documentary evidence in the court of law","correct":true,"visible":false},{"text":"Done in cases of unnatural sudden or suspicious deaths","correct":false,"visible":false},{"text":"External findings are of vital importance","correct":false,"visible":false}]},{"id":1925,"text":"What is the main advantage of R. Virchow's technique of autopsy?","explanation":"The main advantage of Rudolf Virchow's technique of autopsy is that **each organ can be studied in detail**. Virchow's technique, also known as the \"systematic autopsy,\" emphasizes a thorough examination of each organ system to identify and document any abnormalities or pathological changes. This meticulous approach allows for a comprehensive understanding of the disease processes and contributes to accurate diagnosis and research.\r\n\r\nBy carefully examining each organ and its anatomical structures, such as blood vessels, tissues, and cellular components, Virchow's technique enables the pathologist to identify and analyze specific lesions, tumors, inflammatory changes, and other abnormalities. This detailed examination helps in establishing the cause of death, understanding the underlying disease processes, and providing valuable information for clinical management, research, and teaching purposes.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 103","responses":[{"text":"Spread of infection (HIV, HCV) can be limited","correct":false,"visible":false},{"text":"Body can be made available to relatives in 30 minutes","correct":false,"visible":false},{"text":"Each organ can be studied in detail","correct":true,"visible":false},{"text":"Preservation of vascular supply in pathological lesions","correct":false,"visible":false},{"text":"Preservation of anatomico-pathologic relationship","correct":false,"visible":false}]},{"id":1926,"text":"If the cause of death can not be determined even after a thorough post mortem examination, toxicological analysis and histopathological examination, what is the autopsy called?","explanation":"The autopsy conducted when the cause of death cannot be determined even after a thorough post-mortem examination, toxicological analysis, and histopathological examination is called a **negative autopsy**. Despite comprehensive investigations, the specific cause or mechanism of death remains elusive in such cases.\r\n\r\nA negative autopsy can be challenging for both the pathologist and the investigating authorities, as the absence of a clear cause of death may hinder further legal proceedings, insurance claims, or closure for the deceased person's family. It highlights the limitations of current diagnostic techniques and emphasizes the need for continued research and advancements in forensic medicine and pathology.\r\n\r\nIn a negative autopsy, the pathologist provides a detailed report documenting the comprehensive investigations undertaken and the findings observed during the examination. This report helps establish that all possible avenues were explored to determine the cause of death, even if it ultimately remained unknown.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 116.","responses":[{"text":"Incorrect autopsy","correct":false,"visible":false},{"text":"Negative autopsy","correct":true,"visible":false},{"text":"Failure in autopsy","correct":false,"visible":false},{"text":"Unusual autopsy","correct":false,"visible":false},{"text":"Virtual autopsy","correct":false,"visible":false}]},{"id":2070,"text":"What does the common radiological finding in the case of epiglottitis show?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 140.","responses":[{"text":"X-ray chest shows bilateral hilar infiltration with shifting of trachea toward left side","correct":false,"visible":false},{"text":"X-ray neck AP-view reveals \" steeple sign\"","correct":false,"visible":false},{"text":"Bilateral nonhomogeneous infiltrations in both lungs with shifting of trachea on right side","correct":false,"visible":false},{"text":"Lateral x-ray of neck reveal \"thumb printing sign\"","correct":true,"visible":false},{"text":"Lateral x-ray of neck reveal \"steeple sign\"","correct":false,"visible":false}]},{"id":2071,"text":"A 16-year-old tall male comes with sudden shortness of breath while he is playing football. His examination reveals, decreased air entry, hyper resonant percussion note with absent breath sound on the left side of the chest. Which of the following chest X-ray views should be requested to assess the lung pathology?","explanation":"The most appropriate view to evaluate the lung pathology in this case is the **expiratory posteroanterior (P/A) view**.\r\n\r\nThe expiratory P/A view is specifically performed to demonstrate air trapping or a large pneumothorax. It is obtained by taking an X-ray while the patient is instructed to exhale fully. This helps to accentuate the collapsed lung and visualize any air accumulation in the pleural space.\r\n\r\nBy comparing the expiratory P/A view with the normal P/A view, the extent of lung collapse and the presence of any associated complications, such as tension pneumothorax or pneumomediastinum, can be assessed.","reference":"1) Kelly B. The chest radiograph. Ulster Med J. 2012;81(3):143-148. Accessed May 20, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3632825/\r\n\r\n2) Masood I, Elyassi W, Rind W. Medicine. 3rd ed. Majeed Sons; 2018: 233.","responses":[{"text":"Chest X-Ray P/A view","correct":false,"visible":false},{"text":"Expiratory P/A view","correct":true,"visible":false},{"text":"Later decubitus view","correct":false,"visible":false},{"text":"Superior A/P view","correct":false,"visible":false},{"text":"Inspiratory A/P view","correct":false,"visible":false}]},{"id":2096,"text":"A 54-year-old man with a 20-pack year smoking history presents with shortness of breath. On physical examination, he is a thin and cyanotic man in moderate pulmonary distress. His chest shows an increased anteroposterior diameter, and breath sounds are faint with prolonged expiration. Which parameter is most likely found on the pulmonary function tests?","explanation":"In a 54-year-old man with a smoking history and symptoms of shortness of breath, the most likely finding on pulmonary function tests would be a **decreased FEV1: FVC ratio**. \r\n\r\nThe FEV1 (forced expiratory volume in 1 second) measures the amount of air that can be forcefully exhaled in the first second of a forced breath. The FVC (forced vital capacity) measures the total amount of air that can be forcefully exhaled after a maximal inhalation. \r\n\r\nIn obstructive lung diseases, such as chronic obstructive pulmonary disease (COPD), there is an obstruction of airflow, usually due to narrowing of the airways. This results in a decreased FEV1: FVC ratio, as the narrowing of the airways causes a reduction in the ability to forcefully exhale air in the first second.\r\n\r\nThe increased anteroposterior diameter of the chest, faint breath sounds, and prolonged expiration seen in the patient suggest the presence of emphysema, which is a common type of COPD.","reference":"1) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 89.\r\n\r\n 2) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 674.","responses":[{"text":"Decreased FEV1: FVC ratio","correct":true,"visible":false},{"text":"Deceased total lung capacity","correct":false,"visible":false},{"text":"Increased FEV1: FVC ratio","correct":false,"visible":false},{"text":"Normal FEV1: FVC ratio","correct":false,"visible":false},{"text":"Increased forced vital capacity","correct":false,"visible":false}]},{"id":2210,"text":"Goodpasture syndrome is characterized by which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 701.","responses":[{"text":"Caseous necrosis","correct":false,"visible":false},{"text":"Widespread infections","correct":false,"visible":false},{"text":"Hematomas","correct":false,"visible":false},{"text":"Granulomatous lesions","correct":false,"visible":false},{"text":"Nephritis and pneumonitis","correct":true,"visible":false}]},{"id":2211,"text":"Which of the following is not true about pneumonia?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 582, 585.","responses":[{"text":"Pleural effusion is a complication","correct":false,"visible":false},{"text":"Bronchodilators are drug of choice for treatment","correct":true,"visible":false},{"text":"It is an infectious disease","correct":false,"visible":false},{"text":"It is an acute respiratory illness","correct":false,"visible":false},{"text":"There is recently developed x-ray shadowing","correct":false,"visible":false}]},{"id":2214,"text":"What is the most common cause of lung abscess?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 708.","responses":[{"text":"Aspiration of infective material","correct":true,"visible":false},{"text":"Antecedent primary lung infection","correct":false,"visible":false},{"text":"Septic embolism","correct":false,"visible":false},{"text":"Neoplasia","correct":false,"visible":false},{"text":"Trauma","correct":false,"visible":false}]},{"id":2216,"text":"Which of the following chronic obstructive pulmonary disease (COPD) is characterized by mucous gland hyperplasia and hypersecretion in bronchus?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015 678.","responses":[{"text":"Emphysema","correct":false,"visible":false},{"text":"Pneumoconiosis","correct":false,"visible":false},{"text":"Bronchiolitis","correct":false,"visible":false},{"text":"Chronic bronchitis","correct":true,"visible":false},{"text":"Asthma","correct":false,"visible":false}]},{"id":2227,"text":"A young girl complains of a nocturnal cough and shortness of breath, which disturbs her sleep. A diagnosis of bronchial asthma is made. The most important investigation to confirm this diagnosis is?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 569.","responses":[{"text":"Eosinophil count","correct":false,"visible":false},{"text":"Serum IgG level","correct":false,"visible":false},{"text":"X-Ray chest","correct":false,"visible":false},{"text":"Lung function test","correct":true,"visible":false},{"text":"Sputum examination","correct":false,"visible":false}]},{"id":2228,"text":"Which of the following most commonly results in violent asphyxia deaths?","explanation":"**Mechanical asphyxia** is the most common cause of **violent asphyxia deaths**. Mechanical asphyxia occurs when the airway is physically obstructed, preventing the individual from breathing adequately. Examples of mechanical asphyxia include suffocation, strangulation, and compression of the chest or neck. These forms of asphyxia typically result from external forces applied to the body, such as ligature strangulation, manual strangulation, or chest compression. \r\n\r\nPathological asphyxia, environmental asphyxia, iatrogenic asphyxia, and toxic asphyxia are distinct categories of asphyxia but are less commonly associated with violent deaths compared to mechanical asphyxia.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 160.","responses":[{"text":"Iatrogenic asphyxia","correct":false,"visible":false},{"text":"Environmental asphyxia","correct":false,"visible":false},{"text":"Toxic asphyxia","correct":false,"visible":false},{"text":"Mechanical asphyxia","correct":true,"visible":false},{"text":"Pathological asphyxia","correct":false,"visible":false}]},{"id":2383,"text":"What is the causative organism for infection associated with ventilator tubings in the intensive care unit (ICU)?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 703, 707.","responses":[{"text":"Pneumococcus","correct":false,"visible":false},{"text":"Legionella pneumophila","correct":false,"visible":false},{"text":"Methicillin-resistant Staphylococcus aureus (MRSA)","correct":false,"visible":false},{"text":"Pseudomonas aeruginosa","correct":true,"visible":false},{"text":"Moraxella catarrhalis","correct":false,"visible":false}]},{"id":2384,"text":"A 54-year-old diabetic patient came with complaints of fever and cough for the past three days. Chest X-Ray shows a consolidation on the right upper chest. Which of the following is a bad prognostic sign in this condition?","explanation":"In a diabetic patient presenting with fever and cough accompanied by a consolidation on the chest X-ray, a **respiratory rate greater than 30 breaths per minute is a bad prognostic sign**. An increased respiratory rate, also known as tachypnea, indicates respiratory distress and can be indicative of severe lung involvement or respiratory compromise.\r\n\r\nTachypnea is often associated with conditions such as pneumonia, including bacterial pneumonia, which can be a complication in diabetic patients. The rapid breathing is an attempt by the body to compensate for impaired gas exchange and to maintain adequate oxygenation.\r\n\r\nA high respiratory rate suggests significant lung involvement and respiratory compromise, which may require more aggressive management and close monitoring. It indicates a greater degree of respiratory distress and can be associated with a higher risk of respiratory failure and poor outcomes.","reference":"Strauß R, Ewig S, Richter K, König T, Heller G, T. Bauer T. The prognostic significance of respiratory rate in patients with pneumonia. Deutsches Ärzteblatt International. Published July 2014. Accessed May 20, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4150027/","responses":[{"text":"Respiratory rate normal","correct":false,"visible":false},{"text":"Respiratory rate \u003c 15","correct":false,"visible":false},{"text":"Respiratory rate \u003e 30","correct":true,"visible":false},{"text":"Respiratory rate \u003c 30","correct":false,"visible":false},{"text":"Normal urea","correct":false,"visible":false}]},{"id":2385,"text":"A body has been found hanging from a tree. The ligature mark runs obliquely on the neck and ecchymosis adjacent to the ligature mark on the neck muscle is found. This is the feature of:","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 166.","responses":[{"text":"Burking","correct":false,"visible":false},{"text":"Garroting","correct":false,"visible":false},{"text":"Postmortem hanging","correct":false,"visible":false},{"text":"Ante-mortem hanging","correct":true,"visible":false},{"text":"Strangulation","correct":false,"visible":false}]},{"id":2386,"text":"A medico-legal doctor was called by the state law authorities to perform an autopsy on a suspected poisoning case. A detailed study of the stomach and its contents is usually done by which of the following?","explanation":"In a medico-legal autopsy, when a suspected poisoning case is being investigated, a detailed study of the stomach and its contents is usually done by **opening along the greater curvature**. \r\n\r\nOpening the stomach along the greater curvature allows for a thorough examination of the stomach's contents, including any ingested substances or potential toxicants. This approach provides a larger and more accessible area for examination and sampling of the stomach contents.\r\n\r\nBy opening along the greater curvature, the forensic pathologist can carefully inspect the contents, document any abnormalities, and collect samples for further analysis, such as toxicological testing. This technique ensures a comprehensive evaluation of the stomach, aiding in the identification of potential poisoning or other related pathological findings.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 104.","responses":[{"text":"Opening along the lesser curvature","correct":false,"visible":false},{"text":"Opening by incision on its anterior wall","correct":false,"visible":false},{"text":"Opening along the greater curvature","correct":true,"visible":false},{"text":"Opening by a transverse incision","correct":false,"visible":false},{"text":"Can be opened by any side","correct":false,"visible":false}]},{"id":2387,"text":"A 9-month-old child is brought to the clinic for the assessment of cough. On examination, his respiratory rate (R/R) is 52 breaths/minute with no chest retractions and no wheeze on auscultation. How will this child be classified according to Integrated Management of Newborn and Childhood Illnesses (IMNCI)?","explanation":"A 9-month-old child presenting with a cough and a respiratory rate of 52 breaths per minute is consistent with the Integrated Management of Newborn and Childhood Illnesses (IMNCI) guidelines for **pneumonia** assessment. The IMNCI guidelines consider a fast breathing rate (50 breaths per minute or more) in children under 12 months as an important indicator of pneumonia. In addition, the absence of chest retractions and wheezing suggests a milder form of pneumonia.\r\n\r\nAccording to the IMNCI classification, the child's presentation would be categorized as \"Pneumonia.\" This classification is based on the presence of a cough and a fast breathing rate, which are key symptoms considered in the IMNCI guidelines for respiratory illnesses in children.","reference":"INTEGRATED MANAGEMENT OF NEONATAL \u0026 CHILDHOOD ILLNESS. Published 2017. https://phkh.nhsrc.pk/sites/default/files/2020-02/IMNCI%20Chartbooklet%20Pakistan%202017.pdf","responses":[{"text":"Cough and cold","correct":false,"visible":false},{"text":"Pneumonia","correct":true,"visible":false},{"text":"Very severe disease","correct":false,"visible":false},{"text":"Asthma","correct":false,"visible":false},{"text":"Severe pneumonia","correct":false,"visible":false}]},{"id":2388,"text":"A 68-year-old diabetic came with a high-grade fever and a productive cough. There is a bronchial breath sound on the right upper chest. The treating physician suspected community-acquired pneumonia. The commonest cause of community-acquired pneumonia is:","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 707.","responses":[{"text":"Streptococcus pneumoniae","correct":true,"visible":false},{"text":"Mycoplasma pneumoniae","correct":false,"visible":false},{"text":"Pneumocystis jiroveci","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Legionella pneumoniae","correct":false,"visible":false}]},{"id":2390,"text":"In a putrefied body death resulted from drowning, diatoms are found in which of the following organs/viscera?","explanation":"In cases of death resulting from drowning, the presence of diatoms in specific organs/viscera can be helpful in establishing the cause of death. Diatoms are microscopic aquatic organisms that can enter the body during submersion in water and become trapped in various tissues.\r\n\r\nThe correct answer is **Brain and bone marrow**. Diatoms can be found in the brain and bone marrow due to their high vascularity and ability to accumulate diatoms during the drowning process. The presence of diatoms in these tissues provides strong evidence supporting death by drowning.\r\n\r\n- Hilum of right lung and right ear: While diatoms can enter the respiratory system during drowning, they are not typically found in the hilum of the lung or the ear.\r\n- Stomach and left lung: Diatoms are not commonly found in the stomach or the left lung.\r\n- Gall bladder and liver: Diatoms do not typically accumulate in the gall bladder or the liver.\r\n- Ileum and under surface of liver: These locations are not known to be associated with diatom accumulation in cases of drowning.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 182.","responses":[{"text":"Brain and bone marrow","correct":true,"visible":false},{"text":"Stomach and left lung","correct":false,"visible":false},{"text":"Ileum and under surface of liver","correct":false,"visible":false},{"text":"Gall bladder and liver","correct":false,"visible":false},{"text":"Hilum of right lung and right ear","correct":false,"visible":false}]},{"id":2391,"text":"Croup or acute laryngotracheitis is best defined as:","explanation":null,"reference":"Respiratory module, Pediatrics lecture slides, Topic: Upper airway infection management in children, Sub-topic: Croup.","responses":[{"text":"Most patients with croup present between age group 5-7 years, present with fever , dry cough and expiratory stridor with drooling of saliva","correct":false,"visible":false},{"text":"Peak age of presentation is between 3 months to 5 years with history of high grade fever and sore throat for 1 day, patient looks toxic with respiratory distress , inspiratory strider with drooling of saliva","correct":false,"visible":false},{"text":"Peak age of presentation is between 3 months - 5 years with history of flu / cold in previous week , presents with inspiratory stridor, bark like or brassy cough","correct":true,"visible":false},{"text":"Peak age of presentation between 3-5 years, presents with expiratory stridor, severe respiratory distress and high grade fever with drooling of saliva","correct":false,"visible":false},{"text":"Peak age of presentation between 3-5 years, present with expiratory stridor , low grade fever and productive cough with history of viral flu in previous week","correct":false,"visible":false}]},{"id":2392,"text":"A 37-year-old male develops sudden onset of right-sided chest pain associated with severe shortness of breath. There is no other symptom. He was well previously. On examination, he was in distress with a respiratory rate (R/R) of 26 per minute, blood pressure (BP) is 110/70 mmHg and the pulse is 108/min and febrile. Oxygen saturation is 92% and the trachea is central. Chest percussion on the right side has increased resonance with absent breath sound. What is the likely diagnosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 626.","responses":[{"text":"Pneumothorax","correct":true,"visible":false},{"text":"Pneumonia","correct":false,"visible":false},{"text":"Pericarditis","correct":false,"visible":false},{"text":"Emphysema","correct":false,"visible":false},{"text":"Pulmonary embolism","correct":false,"visible":false}]},{"id":2393,"text":"What is the most common type of bronchogenic carcinoma?","explanation":null,"reference":"1) Siddiqui F, Vaqar S, Siddiqui AH. Lung cancer. In: StatPearls. StatPearls Publishing; 2022. Accessed May 20, 2022. http://www.ncbi.nlm.nih.gov/books/NBK482357/\r\n\r\n2) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 709.","responses":[{"text":"Small cell carcinoma","correct":false,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":true,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Bronchoalveolar carcinoma","correct":false,"visible":false}]},{"id":2394,"text":"Pulmonary tuberculosis is caused by which organism?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 371.","responses":[{"text":"Mycobacterium xenopi","correct":false,"visible":false},{"text":"Mycobacterium diphtheriae","correct":false,"visible":false},{"text":"Mycobacterium tuberculosis","correct":true,"visible":false},{"text":"Mycobacterium kansasii","correct":false,"visible":false},{"text":"Mycobacterium malmoense","correct":false,"visible":false}]},{"id":2395,"text":"Atopic asthma is caused by an immune response to environmental allergens. Which one of the following T-helper cells is involved in this exaggerated immune response?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 680.","responses":[{"text":"Combination of Th1 and Th17 response","correct":false,"visible":false},{"text":"Th1 response","correct":false,"visible":false},{"text":"Combination of Th1 and Th2 response","correct":false,"visible":false},{"text":"Th17 response","correct":false,"visible":false},{"text":"Th2 response","correct":true,"visible":false}]},{"id":2396,"text":"What is the causative organism of nosocomial (hospital-acquired) pneumonia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 703.","responses":[{"text":"Legionella pneumophila","correct":false,"visible":false},{"text":"Moraxella catarrhalis","correct":false,"visible":false},{"text":"Pneumococcus","correct":false,"visible":false},{"text":"Pseudomonas aeruginosa","correct":true,"visible":false},{"text":"Klebsiella pneumonia","correct":false,"visible":false}]},{"id":2397,"text":"A 34-year-old male is recently diagnosed with a case of pulmonary tuberculosis and is worried about his urine color since he started taking antitubercular therapy (ATT). Which of the following drug is considered to be the cause?","explanation":null,"reference":"1) Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 845. \r\n\r\n2) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 193.","responses":[{"text":"Pyrazinamide (PZA)","correct":false,"visible":false},{"text":"Rifampicin","correct":true,"visible":false},{"text":"Ethambutol","correct":false,"visible":false},{"text":"Isoniazid (INH)","correct":false,"visible":false},{"text":"Thioacetazone","correct":false,"visible":false}]},{"id":2398,"text":"A neck infection in front of prevertebral fascia may extend:","explanation":null,"reference":"Sutcliffe P, Lasrado S. Anatomy, head and neck, deep cervical neck fascia. In: StatPearls. StatPearls Publishing; 2022. Accessed May 14, 2022. http://www.ncbi.nlm.nih.gov/books/NBK541091/","responses":[{"text":"Into middle mediastinum","correct":false,"visible":false},{"text":"Into inferior mediastinum","correct":false,"visible":false},{"text":"Through superior into anterior mediastinum","correct":false,"visible":false},{"text":"Into superior mediastinum","correct":false,"visible":false},{"text":"Through superior into posterior mediastinum","correct":true,"visible":false}]},{"id":2399,"text":"A 50-year-old man develops truncal obesity and bruising for 5 months. His blood pressure (BP) is 160/95 mmHg and his chest X-ray shows ill-defined 0.4 cm mass involving left hilum of the lung. Bronchial washing shows lymphocyte-like cells but somewhat larger. He was advised to stop smoking. Which of the following is the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 718-719.","responses":[{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Non-Hodgkin lymphoma","correct":false,"visible":false},{"text":"Bronchial carcinoma","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":false,"visible":false},{"text":"Small cell carcinoma","correct":true,"visible":false}]},{"id":2400,"text":"If pulmonary function test shows FEV1/FVC ratio is more than 0.70 with decreased total lung capacity (TLC), then the interpretation would be:","explanation":"Interpreting pulmonary function tests involves assessing different parameters to identify patterns and abnormalities in lung function. In this case, a decreased total lung capacity (TLC) along with an FEV1/FVC ratio of more than 0.70 indicates a **restrictive pattern**. A restrictive lung disease is characterized by reduced lung volumes and limited expansion of the lungs.","reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 699.","responses":[{"text":"Obstructive pattern","correct":false,"visible":false},{"text":"Non-specific reductions in FEV1 and FVC","correct":false,"visible":false},{"text":"Normal","correct":false,"visible":false},{"text":"Mixed pattern","correct":false,"visible":false},{"text":"Restrictive pattern","correct":true,"visible":false}]},{"id":2401,"text":"A 30-year-old female presents with complaints of chest pain, cough along with mucopurulent sputum, and high-grade fever for the last four days. On laboratory assessment, her chest X-ray shows patchy consolidation of both lungs. Which of the following is the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 704.","responses":[{"text":"Lobar pneumonia","correct":false,"visible":false},{"text":"Granulomatous disease of lungs","correct":false,"visible":false},{"text":"Lung abscess","correct":false,"visible":false},{"text":"Bronchopneumonia","correct":true,"visible":false},{"text":"Chronic pneumonia","correct":false,"visible":false}]},{"id":2402,"text":"Central proximal parts of acini formed by respiratory bronchioles are affected in:","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 675.","responses":[{"text":"Centriacinar emphysema","correct":true,"visible":false},{"text":"Distal acinar emphysema","correct":false,"visible":false},{"text":"Panacinar emphysema","correct":false,"visible":false},{"text":"Irregular emphysema","correct":false,"visible":false},{"text":"Interstitial emphysema","correct":false,"visible":false}]},{"id":2403,"text":"Pneumothorax is most commonly associated with:","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 722.","responses":[{"text":"Underlying malignancy","correct":false,"visible":false},{"text":"Asbestos exposure","correct":false,"visible":false},{"text":"Pneumonia","correct":false,"visible":false},{"text":"Sarcoidosis","correct":false,"visible":false},{"text":"Emphysema, asthma and tuberculosis","correct":true,"visible":false}]},{"id":2404,"text":"Tuberculosis granuloma of the lung exhibits characteristic features. Which of the following type of necrosis is seen in tuberculosis?","explanation":"The type of necrosis seen in tuberculosis granulomas of the lung is **caseous necrosis**. Caseous necrosis is a distinctive form of necrosis characterized by a cheesy, friable appearance of the affected tissue. In tuberculosis, it occurs as a result of the immune response to the Mycobacterium tuberculosis infection.\r\n\r\nDuring the course of tuberculosis infection, the immune system attempts to contain the bacteria by forming granulomas, which are aggregates of immune cells. Within these granulomas, the central area undergoes caseous necrosis. The necrotic material appears as a soft, friable, yellow-white cheese-like substance, giving it the name \"caseous.\"\r\n\r\nThe presence of caseous necrosis in tuberculosis granulomas is a hallmark feature of the disease and can be visualized on histological examination of lung tissue. It is an important diagnostic clue for tuberculosis and helps differentiate it from other types of necrosis.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 98.","responses":[{"text":"Coagulative","correct":false,"visible":false},{"text":"Hyaline","correct":false,"visible":false},{"text":"Caseous","correct":true,"visible":false},{"text":"Liquefactive","correct":false,"visible":false},{"text":"Fibrinoid","correct":false,"visible":false}]},{"id":2405,"text":"A patient has signs and symptoms of pneumoconiosis and having asbestosis. Which of the following statement is correct regarding asbestos-related illness?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 691-692.","responses":[{"text":"The most common finding with asbestos exposure is pleural plaques","correct":true,"visible":false},{"text":"Pleural plaques develop most commonly in the apices of the lung pleura","correct":false,"visible":false},{"text":"The most common finding with asbestos exposure is asbestos bodies","correct":false,"visible":false},{"text":"Pleural plaques contain asbestos bodies","correct":false,"visible":false},{"text":"Pleural effusions are a common occurrence in asbestos related disease","correct":false,"visible":false}]},{"id":2406,"text":"A patient with tuberculosis is started on isoniazid (INH) as part of a multidrug regimen. The physician also starts therapy with vitamin B6 at the same time. Which of the following is the main reason for giving the vitamin B6 prophylactically?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 194.","responses":[{"text":"Prevents some adverse effects of INH therapy","correct":true,"visible":false},{"text":"Inhibits metabolism of INH","correct":false,"visible":false},{"text":"Is a cofactor required for activation of INH","correct":false,"visible":false},{"text":"Facilitates INH renal excretion","correct":false,"visible":false},{"text":"Potentiates the antitubercular activity of the INH","correct":false,"visible":false}]},{"id":2407,"text":"The human organ which was first examined by nuclear medicine studies was:","explanation":null,"reference":"1) Historical timeline - snmmi. Accessed May 12, 2022. http://www.snmmi.org/AboutSNMMI/Content.aspx?ItemNumber=4175\r\n\r\n2) Respiratory module, Community-medicine slides, Topic: Nuclear-medicine, Sub-topic: Thyroid.","responses":[{"text":"Pancreas","correct":false,"visible":false},{"text":"Thyroid","correct":true,"visible":false},{"text":"Brain","correct":false,"visible":false},{"text":"Bone","correct":false,"visible":false},{"text":"Heart","correct":false,"visible":false}]},{"id":2408,"text":"A 55-year-old patient suffering from persistent dry cough for the last 2-months due to unknown reasons wants to get a drug without having constipating effects. Which of the following would you prescribe?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 390.","responses":[{"text":"Codeine","correct":false,"visible":false},{"text":"Pholcodine","correct":false,"visible":false},{"text":"Hydrocodone","correct":false,"visible":false},{"text":"Dextromethorphan","correct":true,"visible":false},{"text":"Physostigmine","correct":false,"visible":false}]},{"id":2409,"text":"What is the most important mechanism of action of corticosteroids in asthma?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 354-355.","responses":[{"text":"Direct relaxation of air way smooth muscle","correct":false,"visible":false},{"text":"Decrease in secretion of mucus that occurs in response to vagal activity","correct":false,"visible":false},{"text":"Inhibition of the lymphocytic eosinophilic mucosal inflammation of asthmatic airway","correct":true,"visible":false},{"text":"Increase in ciliary activity","correct":false,"visible":false},{"text":"Cause contraction of engorged vessels in bronchial mucosa","correct":false,"visible":false}]},{"id":2410,"text":"Which of the following agents can reverse the peripheral neuropathy caused by isoniazid?","explanation":"The agent that can reverse the peripheral neuropathy caused by isoniazid is **pyridoxine** (vitamin B6). Isoniazid is an antituberculosis medication that can lead to peripheral neuropathy as a side effect. This occurs due to the depletion of pyridoxine, which is a cofactor for several enzymes involved in neurotransmitter synthesis and nerve function.\r\n\r\nSupplementing with pyridoxine helps prevent and reverse the peripheral neuropathy associated with isoniazid therapy. Pyridoxine acts by replenishing the deficient levels of vitamin B6, which is necessary for maintaining the normal functioning of the peripheral nerves.\r\n\r\nIt is important to note that the use of pyridoxine as a preventive or therapeutic measure for isoniazid-induced peripheral neuropathy is recommended for individuals at high risk, such as those with diabetes, malnutrition, alcoholism, or pregnant women.","reference":"Katzung BG, Kruidering-Hall M, Trevor AJ. Katzung \u0026 Trevor’s Pharmacology Examination \u0026 Board Review. 12th ed. McGraw-Hill Education; 2019: 841.","responses":[{"text":"Folate","correct":false,"visible":false},{"text":"Niacin","correct":false,"visible":false},{"text":"Ascorbic acid","correct":false,"visible":false},{"text":"Thiamine","correct":false,"visible":false},{"text":"Pyridoxine","correct":true,"visible":false}]},{"id":2411,"text":"Which of the following is the correct interpretation of arterial blood gases when pH is 7.30, PCO2 is 24 mmHg and HCO3 is 15 mmol/dL?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 616.","responses":[{"text":"Metabolic alkalosis","correct":false,"visible":false},{"text":"Normal","correct":false,"visible":false},{"text":"Metabolic acidosis","correct":true,"visible":false},{"text":"Respiratory acidosis","correct":false,"visible":false},{"text":"Respiratory alkalosis","correct":false,"visible":false}]},{"id":2447,"text":"A 25-year-old male presents with a one-week history of cough and fever. On examination, he has signs of consolidation. Which of the following signs is more specific for consolidation?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 704.","responses":[{"text":"Decreased chest movement on affected side","correct":false,"visible":false},{"text":"Fine crepitation","correct":false,"visible":false},{"text":"Mediastinal shifting","correct":false,"visible":false},{"text":"Bronchial breathing","correct":false,"visible":false},{"text":"Dull percussion note","correct":true,"visible":false}]},{"id":2449,"text":"Which of the following is an important microscopical feature of acute respiratory distress syndrome (ARDS)?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 94.","responses":[{"text":"Diffuse alveolar damage","correct":true,"visible":false},{"text":"Diffuse bronchiolar damage","correct":false,"visible":false},{"text":"Diffuse septal fibrosis","correct":false,"visible":false},{"text":"Diffuse interstitial fibrosis","correct":false,"visible":false},{"text":"Diffuse bronchoalveolar damage","correct":false,"visible":false}]},{"id":2450,"text":"Host risk factors for the development of chronic obstructive pulmonary disease (COPD) include which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 676.","responses":[{"text":"Outdoor and indoor air pollution","correct":false,"visible":false},{"text":"Low birth weight","correct":false,"visible":false},{"text":"Tobacco smoke","correct":false,"visible":false},{"text":"Biomass solid fuel fires","correct":false,"visible":false},{"text":"Alpha-1 anti-protease deficiency","correct":true,"visible":false}]},{"id":2451,"text":"Which of the following drugs exerts its antimycobacterial activity by interfering with the synthesis of mycolic acid, which are the essential components of mycobacterial cell walls?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 843.","responses":[{"text":"Streptomycin","correct":false,"visible":false},{"text":"Ethambutol","correct":false,"visible":false},{"text":"Pyrazinamide","correct":false,"visible":false},{"text":"Isoniazid","correct":true,"visible":false},{"text":"Rifampin","correct":false,"visible":false}]},{"id":2452,"text":"A 64-year-old patient with hypertension is admitted with uncontrolled blood pressure. After 6 days of admission, he develops a high-grade fever and a productive cough with green sputum. What is the most likely cause of his current problem?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 707.","responses":[{"text":"Hospital acquired pneumonia","correct":true,"visible":false},{"text":"Viral pneumonia","correct":false,"visible":false},{"text":"Cryptogenic organized pneumonia","correct":false,"visible":false},{"text":"Atypical pneumonia","correct":false,"visible":false},{"text":"Community acquired pneumonia","correct":false,"visible":false}]},{"id":2453,"text":"Which one of the following is a prophylactic agent used in cases of bronchial asthma that stabilizes mast cells?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 416.","responses":[{"text":"Metaproterenol","correct":false,"visible":false},{"text":"Ipratropium bromide","correct":false,"visible":false},{"text":"Cromolyn","correct":true,"visible":false},{"text":"Aminophylline","correct":false,"visible":false},{"text":"Terbutaline","correct":false,"visible":false}]},{"id":2454,"text":"Which one of the following is the main cause of resistance of mycobacteria to rifampin?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 846.","responses":[{"text":"Mutation preventing the bindings of rifampin to RNA polymerase","correct":true,"visible":false},{"text":"Mutation resulting in over expression of RNA polymerase","correct":false,"visible":false},{"text":"Increased efflux of rifampin from the bacterial cell by an active pump","correct":false,"visible":false},{"text":"Decreased penetration of rifampin into the bacterial cell","correct":false,"visible":false},{"text":"Increased formation of a enzyme that inactivate rifampin","correct":false,"visible":false}]},{"id":2455,"text":"A 21-year-old female came with a dry cough and shortness of breath for 6 months. For the past week, she is also having nocturnal symptoms. Her treating physician advised a pulmonary function test. \r\nInterpret the following pulmonary function test of this lady: FEV1=50% of predicted, FEV1/FVC=60%, and FVC=82% of predicted.","explanation":"The interpretation of the pulmonary function test (PFT) results for this 21-year-old female shows **an obstructive pattern**. \r\n\r\nThe key parameters to consider are the **FEV1** (forced expiratory volume in 1 second), **FEV1/FVC** (forced expiratory volume in 1 second to forced vital capacity ratio), and **FVC** (forced vital capacity). In this case, the FEV1 is significantly reduced (50% of predicted), indicating airflow limitation. The FEV1/FVC ratio is also decreased (60%), further supporting the presence of airflow obstruction. The FVC is relatively preserved (82% of predicted), indicating that the patient's total lung capacity is not significantly reduced.\r\n\r\nThese findings are consistent with an **obstructive pattern**, suggesting the presence of conditions such as **chronic obstructive pulmonary disease (COPD)** or **asthma**. The reduced FEV1 indicates impaired airflow, and the decreased FEV1/FVC ratio indicates a limitation in expiratory airflow compared to the total lung capacity.","reference":"1) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 89.\r\n\r\n\r\n  \r\n  2) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 674.","responses":[{"text":"Poor effort","correct":false,"visible":false},{"text":"Mixed pattern","correct":false,"visible":false},{"text":"Normal pulmonary function test (PFT)","correct":false,"visible":false},{"text":"Restrictive pattern","correct":false,"visible":false},{"text":"Obstructive pattern","correct":true,"visible":false}]},{"id":2564,"text":"Which of the following diseases involve the destruction of the terminal part of the bronchial tree?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 675.","responses":[{"text":"Asthma","correct":false,"visible":false},{"text":"Bronchiolitis","correct":false,"visible":false},{"text":"Emphysema","correct":true,"visible":false},{"text":"Atelectasis","correct":false,"visible":false},{"text":"Bronchitis","correct":false,"visible":false}]},{"id":2566,"text":"Which type of emphysema involves proximal airway damage?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 90.","responses":[{"text":"Centrilobular","correct":true,"visible":false},{"text":"Paraseptal","correct":false,"visible":false},{"text":"Panacinar","correct":false,"visible":false},{"text":"Distal acinar","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":2567,"text":"Which type of cancer gives the best response to chemotherapy?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 718.","responses":[{"text":"Non-carcinoid tumor","correct":false,"visible":false},{"text":"Small cell lung carcinoma","correct":true,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Carcinoid tumor","correct":false,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false}]},{"id":2568,"text":"Which of the following correctly describes the findings of squamous cell carcinoma?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 709.","responses":[{"text":"Clara cells","correct":false,"visible":false},{"text":"Chromogranin positive cells","correct":false,"visible":false},{"text":"Keratin pearls","correct":true,"visible":false},{"text":"Eosinophillic stain","correct":false,"visible":false},{"text":"Kulchitsky cells","correct":false,"visible":false}]},{"id":2569,"text":"Which of the following is not associated with tuberculosis?","explanation":null,"reference":"1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 374-375.\r\n\r\n2) Kuhajda I, Zarogoulidis K, Tsirgogianni K, et al. Lung abscess-etiology, diagnostic and treatment options. Annals of Translational Medicine. Published August 2015. \r\n\r\n3) Wei M, Yongjie Zhao, Zhuoyu Qian, et al. Pneumonia caused by Mycobacterium tuberculosis. Microbes and Infection. Published 2020. Accessed May 20, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7297158/","responses":[{"text":"Cavitary fibrous lesion","correct":false,"visible":false},{"text":"Ghon complex","correct":false,"visible":false},{"text":"Advanced fibrous lesion","correct":false,"visible":false},{"text":"Lung abscess","correct":true,"visible":false},{"text":"Bronchogenic pneumonia","correct":false,"visible":false}]},{"id":2736,"text":"A 34-year-old male presents with a history of altered consciousness for one day. Arterial blood gas (ABG) results show pH 7.31, PCO2 = 24 mmHg, HCO3 = 15 mmol/L. Which of the following is the most likely condition?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 616.","responses":[{"text":"Respiratory alkalosis","correct":false,"visible":false},{"text":"Normal","correct":false,"visible":false},{"text":"Metabolic acidosis","correct":true,"visible":false},{"text":"Respiratory acidosis","correct":false,"visible":false},{"text":"Metabolic alkalosis","correct":false,"visible":false}]}
]

export default a